/// Safe string truncation that respects UTF-8 character boundaries
/// Best-effort per-request cost estimate in USD for OpenRouter-backed requests.
/// Returns 0.0 when pricing is unavailable rather than guessing with hardcoded rates.
fn estimate_cost_usd(provider: &str, model: &str, input_tokens: u64, output_tokens: u64) -> f64 {
    if !provider.trim().eq_ignore_ascii_case("openrouter") {
        return 0.0;
    }
    crate::channels::http::estimate_cost_from_pricing_cache(model, input_tokens, output_tokens)
        .unwrap_or(0.0)
}

fn safe_truncate(s: &str, max_chars: usize) -> String {
    if s.chars().count() <= max_chars {
        s.to_string()
    } else {
        format!("{}...", s.chars().take(max_chars).collect::<String>())
    }
}

fn floor_char_boundary(text: &str, index: usize) -> usize {
    let mut idx = index.min(text.len());
    while idx > 0 && !text.is_char_boundary(idx) {
        idx -= 1;
    }
    idx
}

fn next_chunk_boundary(text: &str, pos: usize, max_bytes: usize) -> usize {
    if pos >= text.len() {
        return text.len();
    }
    let raw_end = floor_char_boundary(text, pos.saturating_add(max_bytes).min(text.len()));
    if raw_end <= pos {
        return text[pos..]
            .char_indices()
            .nth(1)
            .map(|(offset, _)| pos + offset)
            .unwrap_or(text.len());
    }
    if raw_end == text.len() {
        return raw_end;
    }
    let window = &text[pos..raw_end];
    window
        .rfind('\n')
        .or_else(|| window.rfind(' '))
        .map(|offset| pos + offset + 1)
        .filter(|snap| *snap > pos)
        .unwrap_or(raw_end)
}

fn notification_push_signature(message: &str) -> String {
    let mut out = String::with_capacity(message.len().min(240));
    let mut prev_space = false;
    for ch in message.chars() {
        if ch.is_whitespace() {
            if !prev_space {
                out.push(' ');
                prev_space = true;
            }
            continue;
        }
        prev_space = false;
        out.push(ch.to_ascii_lowercase());
        if out.len() >= 220 {
            break;
        }
    }
    out.trim().to_string()
}

fn extract_http_urls(text: &str) -> Vec<String> {
    let mut urls = Vec::new();
    let mut seen = HashSet::new();
    for token in text.split_whitespace() {
        let candidate = token
            .trim_matches(|c: char| {
                matches!(
                    c,
                    '"' | '\'' | '`' | '<' | '>' | '(' | ')' | '[' | ']' | '{' | '}'
                )
            })
            .trim_end_matches(['.', ',', ';', ':', '!', '?', '`'])
            .trim();
        if candidate.starts_with("http://") || candidate.starts_with("https://") {
            let normalized = candidate.to_string();
            if seen.insert(normalized.clone()) {
                urls.push(normalized);
            }
        }
    }
    urls
}

fn action_message_hint(arguments: &serde_json::Value) -> Option<String> {
    let keys = ["query", "task", "prompt", "message", "description", "title"];
    for key in keys {
        if let Some(value) = arguments.get(key).and_then(|v| v.as_str()) {
            let trimmed = value.trim();
            if !trimmed.is_empty() {
                return Some(safe_truncate(trimmed, 500));
            }
        }
    }
    None
}

fn is_sensitive_tool_call_argument_key(key: &str) -> bool {
    matches!(
        key.trim().to_ascii_lowercase().as_str(),
        "token"
            | "api_key"
            | "apikey"
            | "secret"
            | "password"
            | "authorization"
            | "auth"
            | "cookie"
            | "cookies"
            | "headers"
    )
}

fn tool_call_request_argument_value_preview(
    key: &str,
    value: &serde_json::Value,
) -> Option<String> {
    let key = key.trim().to_ascii_lowercase();
    match value {
        serde_json::Value::String(text) => {
            let trimmed = text.trim();
            if trimmed.is_empty() {
                return None;
            }
            let display = if key == "url" {
                extract_url_host_for_summary(trimmed).unwrap_or_else(|| safe_truncate(trimmed, 80))
            } else {
                safe_truncate(trimmed, 80)
            };
            serde_json::to_string(&display).ok()
        }
        serde_json::Value::Number(number) => Some(number.to_string()),
        serde_json::Value::Bool(value) => Some(value.to_string()),
        serde_json::Value::Array(items) => {
            if items.is_empty() {
                None
            } else {
                Some(format!("{} items", items.len()))
            }
        }
        serde_json::Value::Object(map) => {
            if map.is_empty() {
                None
            } else {
                Some(format!("{} keys", map.len()))
            }
        }
        serde_json::Value::Null => None,
    }
}

fn tool_call_request_argument_preview(arguments: &serde_json::Value) -> Option<String> {
    let map = arguments.as_object()?;
    let preferred_keys = [
        "action",
        "operation",
        "query",
        "task",
        "prompt",
        "message",
        "description",
        "title",
        "topic",
        "url",
        "file_path",
        "path",
        "id",
        "name",
        "depth",
        "backend",
        "max_sources",
    ];
    let mut seen_keys = HashSet::new();
    let mut parts = Vec::new();

    for key in preferred_keys {
        let Some(value) = map.get(key) else {
            continue;
        };
        let Some(preview) = tool_call_request_argument_value_preview(key, value) else {
            continue;
        };
        parts.push(format!("{key}={preview}"));
        seen_keys.insert(key);
        if parts.len() >= 3 {
            break;
        }
    }

    if parts.is_empty() {
        for (key, value) in map {
            if key.starts_with('_')
                || seen_keys.contains(key.as_str())
                || is_sensitive_tool_call_argument_key(key)
            {
                continue;
            }
            let Some(preview) = tool_call_request_argument_value_preview(key, value) else {
                continue;
            };
            parts.push(format!("{key}={preview}"));
            if parts.len() >= 3 {
                break;
            }
        }
    }

    if !parts.is_empty() {
        return Some(parts.join(", "));
    }

    let visible_keys = map
        .keys()
        .filter(|key| !key.starts_with('_') && !is_sensitive_tool_call_argument_key(key))
        .take(3)
        .cloned()
        .collect::<Vec<_>>();
    if visible_keys.is_empty() {
        None
    } else {
        Some(format!("keys={}", visible_keys.join("|")))
    }
}

fn format_tool_call_request_preview(call: &crate::core::llm::ToolCall) -> String {
    let name = call.name.trim();
    match tool_call_request_argument_preview(&call.arguments) {
        Some(arguments) if !arguments.is_empty() => format!("{name}({arguments})"),
        _ => name.to_string(),
    }
}

fn drop_capability_acquire_when_extension_pack_route_exists(
    tool_calls: Vec<crate::core::llm::ToolCall>,
) -> Vec<crate::core::llm::ToolCall> {
    let has_extension_pack_route = tool_calls
        .iter()
        .any(|call| call.name.starts_with("extension_pack_"));
    if !has_extension_pack_route {
        return tool_calls;
    }
    tool_calls
        .into_iter()
        .filter(|call| !call.name.eq_ignore_ascii_case("capability_acquire"))
        .collect()
}

fn default_automation_validation_for_action(action_name: &str) -> AutomationValidation {
    match action_name {
        "daily_brief" | "goal_progress_report" | "goal_reminder" => AutomationValidation {
            mode: AutomationValidationMode::NonEmptyResult,
            ..AutomationValidation::default()
        },
        "moltbook" | "gmail" | "google_calendar" | "notion" | "github" | "twitter" => {
            AutomationValidation {
                mode: AutomationValidationMode::StructuredSuccess,
                ..AutomationValidation::default()
            }
        }
        _ => AutomationValidation {
            mode: AutomationValidationMode::NonEmptyResult,
            ..AutomationValidation::default()
        },
    }
}

fn should_retry_background_action(action_name: &str) -> bool {
    !matches!(action_name, "goal" | "goal_progress_report")
}

fn automation_trigger_label(channel: &str, action_name: &str) -> String {
    if channel.eq_ignore_ascii_case("watcher") {
        "watcher".to_string()
    } else if action_name == "daily_brief" {
        "scheduler_daily_brief".to_string()
    } else {
        "scheduler".to_string()
    }
}

fn parse_register_tool_alias_command(message: &str) -> Option<(String, String)> {
    let trimmed = message.trim();
    let lowered = trimmed.to_ascii_lowercase();
    let prefixes = ["/tool register "];
    let prefix = prefixes.iter().find(|p| lowered.starts_with(**p))?;
    let rest = trimmed[prefix.len()..].trim();
    if rest.is_empty() {
        return None;
    }

    let split_pair = if let Some((left, right)) = rest.split_once("->") {
        Some((left.trim(), right.trim()))
    } else if let Some((left, right)) = rest.split_once('=') {
        Some((left.trim(), right.trim()))
    } else {
        None
    }?;

    let (tool_name, integration_id) = split_pair;
    if tool_name.is_empty() || integration_id.is_empty() {
        return None;
    }
    Some((tool_name.to_string(), integration_id.to_string()))
}

fn parse_use_model_command(message: &str) -> Option<String> {
    let trimmed = message.trim();
    if trimmed.is_empty() {
        return None;
    }
    let lower = trimmed.to_ascii_lowercase();
    let prefixes = [
        "/usemodel -",
        "/usemodel:",
        "/usemodel ",
        "/use model -",
        "/use model:",
        "/use model ",
    ];
    for prefix in prefixes {
        if lower.starts_with(prefix) && trimmed.len() >= prefix.len() {
            let value = trimmed[prefix.len()..]
                .trim()
                .trim_matches(|c| matches!(c, '"' | '\'' | '`'))
                .trim();
            if value.is_empty() || value.contains('\n') || value.contains('\r') {
                return None;
            }
            return Some(value.to_string());
        }
    }
    None
}

fn normalize_model_match_token(raw: &str) -> String {
    raw.trim()
        .trim_matches(|c| matches!(c, '"' | '\'' | '`'))
        .to_ascii_lowercase()
}

fn compact_model_match_token(raw: &str) -> String {
    normalize_model_match_token(raw)
        .chars()
        .filter(|c| c.is_ascii_alphanumeric())
        .collect()
}

fn merge_app_llm_env_from_providers(
    provider_refs: &[&crate::core::LlmProvider],
) -> std::collections::HashMap<String, String> {
    let mut merged: std::collections::HashMap<String, String> = std::collections::HashMap::new();
    for provider in provider_refs {
        for (k, v) in provider.app_env_vars() {
            if v.trim().is_empty() || v == "[ENCRYPTED]" {
                continue;
            }
            merged.entry(k).or_insert(v);
        }
    }

    if !merged.contains_key("OPENROUTER_API_KEY")
        && provider_refs.iter().any(|provider| {
            matches!(
                provider,
                crate::core::LlmProvider::OpenAI { api_key, base_url, .. }
                    if !api_key.trim().is_empty()
                        && base_url
                            .as_deref()
                            .unwrap_or("")
                            .to_ascii_lowercase()
                            .contains("openrouter")
            )
        })
    {
        if let Some(v) = merged.get("OPENAI_API_KEY").cloned() {
            merged.insert("OPENROUTER_API_KEY".to_string(), v);
        }
    }
    if !merged.contains_key("OPENAI_KEY") {
        if let Some(v) = merged.get("OPENAI_API_KEY").cloned() {
            merged.insert("OPENAI_KEY".to_string(), v);
        }
    }
    if !merged.contains_key("OPENAI_TOKEN") {
        if let Some(v) = merged.get("OPENAI_API_KEY").cloned() {
            merged.insert("OPENAI_TOKEN".to_string(), v);
        }
    }

    merged
}

