fn monitoring_code_execute_has_structured_poller_output(
    watch_intent: bool,
    tool_calls: &[crate::core::llm::ToolCall],
    _all_executed_tool_calls: &[crate::core::llm::ToolCall],
    batch: &tool_execution::ToolExecutionBatch,
) -> bool {
    if !watch_intent
        || !tool_calls
            .iter()
            .any(|call| call.name.eq_ignore_ascii_case("code_execute"))
    {
        return false;
    }

    let metadata = successful_code_execute_execution_metadata(batch);
    if metadata.iter().any(|state| state.ready_for_watch) {
        return false;
    }

    successful_code_execute_outputs(batch)
        .into_iter()
        .any(|output| {
            Agent::extract_structured_watcher_condition_payload(&output.content).is_some()
        })
}

fn watch_condition_from_arguments(
    arguments: &serde_json::Value,
) -> Option<crate::core::watcher::WatchCondition> {
    serde_json::from_value(arguments.get("condition")?.clone()).ok()
}

fn normalized_watch_condition_path(path: &str) -> Option<String> {
    let trimmed = path.trim();
    if trimmed.is_empty() {
        return None;
    }
    Some(if trimmed.starts_with('$') {
        trimmed.to_string()
    } else {
        format!("$.{}", trimmed.trim_start_matches('.'))
    })
}

fn numeric_watch_condition_value_from_payload(
    payload: &serde_json::Value,
    path: &str,
) -> Option<(String, serde_json::Value)> {
    let normalized = normalized_watch_condition_path(path)?;
    let value = Agent::json_value_at_watch_condition_path(payload, &normalized)?;
    matches!(value, serde_json::Value::Number(_)).then(|| (normalized, value.clone()))
}

fn synthesized_post_baseline_watch_condition_from_payload(
    prior_condition: &crate::core::watcher::WatchCondition,
    payload: &serde_json::Value,
) -> Option<crate::core::watcher::WatchCondition> {
    let (path, operator, baseline_value) = match &prior_condition.matcher {
        crate::core::watcher::WatchConditionMatcher::JsonPredicate { path, operator, .. } => {
            let (normalized_path, current_value) =
                numeric_watch_condition_value_from_payload(payload, path)?;
            let comparison_operator = match operator {
                crate::core::watcher::WatchConditionOperator::Gt
                | crate::core::watcher::WatchConditionOperator::Gte => {
                    crate::core::watcher::WatchConditionOperator::Gt
                }
                crate::core::watcher::WatchConditionOperator::Lt
                | crate::core::watcher::WatchConditionOperator::Lte => {
                    crate::core::watcher::WatchConditionOperator::Lt
                }
                _ => return None,
            };
            (normalized_path, comparison_operator, current_value)
        }
        _ => return None,
    };

    let baseline_label = path.trim_start_matches("$.").replace(['.', '_'], " ");
    Some(crate::core::watcher::WatchCondition {
        description: format!(
            "Trigger when {} changes beyond the current baseline of {}",
            baseline_label, baseline_value
        ),
        matcher: crate::core::watcher::WatchConditionMatcher::JsonPredicate {
            path,
            operator,
            value: Some(baseline_value),
        },
    })
}

fn synthesize_monitoring_watch_call_from_recent_code_execute(
    tool_calls: &[crate::core::llm::ToolCall],
    all_executed_tool_calls: &[crate::core::llm::ToolCall],
    batch: &tool_execution::ToolExecutionBatch,
) -> Option<crate::core::llm::ToolCall> {
    let (code_execute_call, payload) =
        tool_calls
            .iter()
            .enumerate()
            .rev()
            .find_map(|(index, call)| {
                if !call.name.eq_ignore_ascii_case("code_execute")
                    || !tool_batch_output_succeeded(batch, index)
                {
                    return None;
                }
                let output = batch.outputs.get(index)?;
                let payload = Agent::extract_structured_watcher_condition_payload(&output.content)?;
                Some((call, payload))
            })?;

    let prior_watch = all_executed_tool_calls
        .iter()
        .rev()
        .find(|call| call.name.eq_ignore_ascii_case("watch"))?;
    let prior_condition = watch_condition_from_arguments(&prior_watch.arguments)?;
    let payload_text = payload.to_string();
    let synthesized_condition =
        match Agent::evaluate_watch_condition_without_llm(&prior_condition, &payload_text) {
            Some(Ok(false)) => prior_condition,
            Some(Ok(true)) => {
                synthesized_post_baseline_watch_condition_from_payload(&prior_condition, &payload)?
            }
            Some(Err(_)) | None => return None,
        };

    let mut arguments = prior_watch
        .arguments
        .as_object()
        .cloned()
        .unwrap_or_default();
    arguments.insert(
        "poll_action".to_string(),
        serde_json::Value::String("code_execute".to_string()),
    );
    arguments.insert(
        "poll_arguments".to_string(),
        code_execute_call.arguments.clone(),
    );
    arguments.insert(
        "condition".to_string(),
        serde_json::to_value(&synthesized_condition).ok()?,
    );
    arguments
        .entry("notify_channel".to_string())
        .or_insert_with(|| serde_json::Value::String("preferred".to_string()));

    Some(crate::core::llm::ToolCall {
        id: format!("synthetic_watch_{}", uuid::Uuid::new_v4()),
        name: "watch".to_string(),
        arguments: serde_json::Value::Object(arguments),
    })
}

