fn file_write_call_entry(call: &crate::core::llm::ToolCall) -> Option<(PathBuf, String)> {
    if call.name != "file_write" {
        return None;
    }
    let path = call
        .arguments
        .get("path")
        .and_then(|value| value.as_str())
        .or_else(|| {
            call.arguments
                .get("file_path")
                .and_then(|value| value.as_str())
        })
        .or_else(|| {
            call.arguments
                .get("filename")
                .and_then(|value| value.as_str())
        })
        .map(str::trim)
        .filter(|value| !value.is_empty())?;
    let content = call
        .arguments
        .get("content")
        .and_then(|value| value.as_str())
        .or_else(|| call.arguments.get("text").and_then(|value| value.as_str()))
        .or_else(|| call.arguments.get("body").and_then(|value| value.as_str()))?;
    Some((PathBuf::from(path), content.to_string()))
}

fn app_workspace_root_for_written_path(path: &Path) -> Option<PathBuf> {
    let normalized = path.to_string_lossy().replace('\\', "/");
    if !normalized.starts_with("/app/") {
        return None;
    }

    let segments: Vec<&str> = normalized
        .split('/')
        .filter(|part| !part.is_empty())
        .collect();
    if segments.len() < 2 || segments.first().copied() != Some("app") {
        return None;
    }

    if segments.get(1).copied() == Some("data") && segments.get(2).copied() == Some("apps") {
        if segments.get(3).copied() == Some("new") {
            let slug = segments.get(4).copied()?;
            return Some(PathBuf::from(format!("/app/data/apps/new/{}", slug)));
        }
        return None;
    }

    if segments.get(1).copied() == Some("data") {
        let slug = segments.get(2).copied()?;
        return Some(PathBuf::from(format!("/app/data/{}", slug)));
    }

    if segments.len() == 2 {
        return Some(PathBuf::from("/app"));
    }

    Some(PathBuf::from(format!("/app/{}", segments[1])))
}

type RecentDeployWriteGroup = (PathBuf, Vec<(PathBuf, String)>, usize);

fn collect_recent_deployable_file_writes(
    current_turn_calls: &[crate::core::llm::ToolCall],
    prior_calls: &[crate::core::llm::ToolCall],
) -> Option<(PathBuf, Vec<(PathBuf, String)>)> {
    let combined: Vec<&crate::core::llm::ToolCall> = prior_calls
        .iter()
        .chain(current_turn_calls.iter())
        .collect();
    let recent_start = combined
        .iter()
        .rposition(|call| {
            if call.name != "app_deploy" {
                return false;
            }
            let normalized = Agent::normalize_app_deploy_arguments(&call.arguments);
            normalized
                .get("repo_url")
                .and_then(|value| value.as_str())
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .is_some()
                || normalized
                    .get("files")
                    .and_then(|value| value.as_object())
                    .is_some_and(|files| !files.is_empty())
        })
        .map(|idx| idx + 1)
        .unwrap_or_else(|| combined.len().saturating_sub(24));

    let mut grouped: HashMap<String, RecentDeployWriteGroup> = HashMap::new();
    for (relative_idx, call) in combined[recent_start..].iter().enumerate() {
        let Some((path, content)) = file_write_call_entry(call) else {
            continue;
        };
        let Some(root) = app_workspace_root_for_written_path(&path) else {
            continue;
        };
        let key = root.to_string_lossy().to_string();
        let entry = grouped.entry(key).or_insert_with(|| (root, Vec::new(), 0));
        entry.1.push((path, content));
        entry.2 = relative_idx;
    }

    grouped
        .into_values()
        .max_by(|left, right| {
            left.1
                .len()
                .cmp(&right.1.len())
                .then_with(|| left.2.cmp(&right.2))
        })
        .map(|(root, writes, _)| (root, writes))
}

fn deploy_relative_file_path(path: &Path, base: &Path) -> Option<String> {
    let relative = path.strip_prefix(base).unwrap_or(path);
    let mut parts = Vec::new();
    for component in relative.components() {
        match component {
            std::path::Component::Normal(value) => {
                parts.push(value.to_string_lossy().replace('\\', "/"));
            }
            std::path::Component::CurDir => {}
            _ => return None,
        }
    }
    if parts.is_empty() {
        path.file_name()
            .map(|value| value.to_string_lossy().replace('\\', "/"))
    } else {
        Some(parts.join("/"))
    }
}

fn synthesize_app_deploy_files_from_recent_writes(
    current_turn_calls: &[crate::core::llm::ToolCall],
    prior_calls: &[crate::core::llm::ToolCall],
) -> Option<serde_json::Map<String, serde_json::Value>> {
    let (base, mut writes) =
        collect_recent_deployable_file_writes(current_turn_calls, prior_calls)?;
    if writes.is_empty() {
        return None;
    }

    let mut files = serde_json::Map::new();
    for (path, content) in writes.drain(..) {
        let Some(relative) = deploy_relative_file_path(&path, &base) else {
            continue;
        };
        if relative.trim().is_empty() {
            continue;
        }
        files.insert(relative, serde_json::Value::String(content));
    }
    if files.is_empty() {
        None
    } else {
        Some(files)
    }
}

fn rebase_static_site_files_for_deploy(
    files: &serde_json::Map<String, serde_json::Value>,
) -> serde_json::Map<String, serde_json::Value> {
    for prefix in ["public/", "dist/", "build/"] {
        let index_name = format!("{}index.html", prefix);
        if !files.contains_key(&index_name) || files.contains_key("index.html") {
            continue;
        }
        let mut rebased = files.clone();
        let mut moved_any = false;
        for (path, content) in files {
            let Some(stripped) = path.strip_prefix(prefix) else {
                continue;
            };
            if stripped.trim().is_empty() {
                continue;
            }
            moved_any = true;
            rebased
                .entry(stripped.to_string())
                .or_insert_with(|| content.clone());
        }
        if moved_any {
            return rebased;
        }
    }
    files.clone()
}

fn infer_entry_command_from_synthesized_files(
    files: &serde_json::Map<String, serde_json::Value>,
) -> Option<String> {
    let mut python_files: Vec<(String, String)> = Vec::new();
    let mut has_html = false;
    let mut has_package_json = false;
    let mut js_entry_candidates: Vec<String> = Vec::new();

    for (path, content) in files {
        let normalized = path.trim().replace('\\', "/");
        if normalized.is_empty() {
            continue;
        }
        let lower_path = normalized.to_ascii_lowercase();
        let text = content.as_str().unwrap_or("").to_string();
        if lower_path.ends_with(".html") {
            has_html = true;
        }
        if lower_path == "package.json" {
            has_package_json = true;
        }
        if matches!(
            lower_path.as_str(),
            "server.js" | "app.js" | "index.js" | "main.js" | "server.mjs" | "app.mjs"
        ) {
            js_entry_candidates.push(normalized.clone());
        }
        if lower_path.ends_with(".py") {
            python_files.push((normalized, text));
        }
    }

    for (path, content) in &python_files {
        let lower = content.to_ascii_lowercase();
        if lower.contains("import streamlit") || lower.contains("streamlit.") {
            return Some(format!(
                "streamlit run {} --server.address 0.0.0.0 --server.port {{PORT}}",
                path
            ));
        }
    }

    for (path, content) in &python_files {
        let lower = content.to_ascii_lowercase();
        if lower.contains("fastapi") {
            let module = Path::new(path)
                .file_stem()
                .map(|value| value.to_string_lossy().to_string())
                .filter(|value| !value.trim().is_empty())
                .unwrap_or_else(|| "app".to_string());
            return Some(format!(
                "uvicorn {}:app --host 0.0.0.0 --port {{PORT}}",
                module
            ));
        }
    }

    for (path, content) in &python_files {
        let lower = content.to_ascii_lowercase();
        if lower.contains("flask") {
            return Some(format!("python {}", path));
        }
    }

    if let Some(entry) = js_entry_candidates.first() {
        return Some(format!("node {}", entry));
    }
    if has_package_json {
        return Some("npm start".to_string());
    }
    if has_html {
        return None;
    }
    None
}

fn synthesize_missing_app_deploy_tool_call_from_recent_writes(
    current_turn_calls: &[crate::core::llm::ToolCall],
    prior_calls: &[crate::core::llm::ToolCall],
) -> Option<crate::core::llm::ToolCall> {
    let (base, writes) = collect_recent_deployable_file_writes(current_turn_calls, prior_calls)?;
    if writes.is_empty() {
        return None;
    }

    let base_normalized = base.to_string_lossy().replace('\\', "/");
    let is_new_app_staging_root = base_normalized.starts_with("/app/data/apps/new/");
    if !base_normalized.starts_with("/app/") || base_normalized == "/app" {
        return None;
    }
    if base_normalized.starts_with("/app/data/apps/") && !is_new_app_staging_root {
        return None;
    }

    let mut files = serde_json::Map::new();
    for (path, content) in writes {
        let Some(relative) = deploy_relative_file_path(&path, &base) else {
            continue;
        };
        if relative.trim().is_empty() {
            continue;
        }
        files.insert(relative, serde_json::Value::String(content));
    }
    if files.is_empty() {
        return None;
    }

    let file_keys = files.keys().cloned().collect::<Vec<_>>();
    let has_html = file_keys.iter().any(|key| {
        key.eq_ignore_ascii_case("index.html") || key.to_ascii_lowercase().ends_with(".html")
    });
    let mut deploy_files = if has_html {
        rebase_static_site_files_for_deploy(&files)
    } else {
        files.clone()
    };
    let entry_command = infer_entry_command_from_synthesized_files(&deploy_files);
    let still_has_html = deploy_files.keys().any(|key| {
        key.eq_ignore_ascii_case("index.html") || key.to_ascii_lowercase().ends_with(".html")
    });
    if !still_has_html && entry_command.is_none() {
        return None;
    }

    let title = base
        .file_name()
        .map(|value| humanize_tool_name(&value.to_string_lossy()))
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| "App".to_string());

    let mut arguments = serde_json::Map::new();
    arguments.insert("title".to_string(), serde_json::json!(title));
    arguments.insert(
        "files".to_string(),
        serde_json::Value::Object(std::mem::take(&mut deploy_files)),
    );
    arguments.insert(
        "runtime_preference".to_string(),
        serde_json::json!("container"),
    );
    arguments.insert("expose_public".to_string(), serde_json::json!(false));
    arguments.insert("allow_duplicate".to_string(), serde_json::json!(true));
    if let Some(entry_command) = entry_command {
        arguments.insert("runtime_required".to_string(), serde_json::json!(true));
        arguments.insert(
            "runtime_reason".to_string(),
            serde_json::json!("inferred server/runtime from staged app files"),
        );
        arguments.insert(
            "entry_command".to_string(),
            serde_json::json!(entry_command),
        );
    }

    Some(crate::core::llm::ToolCall {
        id: "recovered_app_deploy".to_string(),
        name: "app_deploy".to_string(),
        arguments: serde_json::Value::Object(arguments),
    })
}

fn repair_app_deploy_tool_call_from_recent_writes(
    call: &crate::core::llm::ToolCall,
    current_turn_calls: &[crate::core::llm::ToolCall],
    prior_calls: &[crate::core::llm::ToolCall],
) -> Option<crate::core::llm::ToolCall> {
    if call.name != "app_deploy" {
        return None;
    }
    let normalized = Agent::normalize_app_deploy_arguments(&call.arguments);
    if normalized
        .get("files")
        .and_then(|value| value.as_object())
        .is_some_and(|files| !files.is_empty())
    {
        return None;
    }
    let files = synthesize_app_deploy_files_from_recent_writes(current_turn_calls, prior_calls)?;
    let mut repaired = normalized
        .as_object()
        .cloned()
        .unwrap_or_else(serde_json::Map::new);
    repaired.insert("files".to_string(), serde_json::Value::Object(files));
    Some(crate::core::llm::ToolCall {
        id: call.id.clone(),
        name: call.name.clone(),
        arguments: serde_json::Value::Object(repaired),
    })
}

struct GeneratedAppDeployStagingPlan {
    tool_calls: Vec<crate::core::llm::ToolCall>,
    staging_root: String,
    file_count: usize,
}

fn normalize_generated_app_deploy_relative_path(path: &str) -> Option<String> {
    let trimmed = path.trim().replace('\\', "/");
    if trimmed.is_empty() {
        return None;
    }

    let mut parts = Vec::new();
    for component in Path::new(&trimmed).components() {
        match component {
            std::path::Component::Normal(value) => {
                parts.push(value.to_string_lossy().replace('\\', "/"));
            }
            std::path::Component::CurDir => {}
            _ => return None,
        }
    }

    if parts.is_empty() {
        None
    } else {
        Some(parts.join("/"))
    }
}

fn rewrite_generated_app_deploy_to_staged_writes(
    call: &crate::core::llm::ToolCall,
    current_turn_calls: &[crate::core::llm::ToolCall],
    prior_calls: &[crate::core::llm::ToolCall],
) -> Option<GeneratedAppDeployStagingPlan> {
    if call.name != "app_deploy" {
        return None;
    }

    let normalized = Agent::normalize_app_deploy_arguments(&call.arguments);
    if normalized
        .get("repo_url")
        .and_then(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .is_some()
    {
        return None;
    }

    let files = normalized
        .get("files")
        .and_then(|value| value.as_object())
        .filter(|files| !files.is_empty())?;
    let staging_root = collect_recent_deployable_file_writes(current_turn_calls, prior_calls)
        .map(|(root, _)| root)
        .unwrap_or_else(|| {
            let slug = normalized
                .get("title")
                .and_then(|value| value.as_str())
                .map(preference_subject_slug)
                .filter(|value| !value.trim().is_empty())
                .unwrap_or_else(|| "generated_app".to_string());
            PathBuf::from(format!("/app/data/apps/new/{}", slug))
        });
    let staging_root_str = staging_root.to_string_lossy().replace('\\', "/");
    let mut staged_calls = Vec::new();

    for (index, (path, content)) in files.iter().enumerate() {
        let Some(relative_path) = normalize_generated_app_deploy_relative_path(path) else {
            continue;
        };
        let staged_path = format!(
            "{}/{}",
            staging_root_str.trim_end_matches('/'),
            relative_path
        );
        let staged_content = content
            .as_str()
            .map(str::to_string)
            .unwrap_or_else(|| content.to_string());
        staged_calls.push(crate::core::llm::ToolCall {
            id: format!("{}-stage-{}", call.id, index + 1),
            name: "file_write".to_string(),
            arguments: serde_json::json!({
                "path": staged_path,
                "content": staged_content,
            }),
        });
    }

    if staged_calls.is_empty() {
        return None;
    }

    let mut stripped_args = normalized
        .as_object()
        .cloned()
        .unwrap_or_else(serde_json::Map::new);
    stripped_args.remove("files");
    staged_calls.push(crate::core::llm::ToolCall {
        id: call.id.clone(),
        name: call.name.clone(),
        arguments: serde_json::Value::Object(stripped_args),
    });

    Some(GeneratedAppDeployStagingPlan {
        file_count: staged_calls.len().saturating_sub(1),
        tool_calls: staged_calls,
        staging_root: staging_root_str,
    })
}

#[cfg(test)]
fn strip_diagnostic_evidence_sections(response: &str) -> String {
    let normalized = response.replace("\r\n", "\n");
    let mut kept = Vec::new();
    for paragraph in normalized.split("\n\n") {
        let trimmed = paragraph.trim();
        if trimmed.is_empty() {
            continue;
        }
        let lower = trimmed.replace(['—', '–'], "-").to_ascii_lowercase();
        let is_diagnostic_evidence = lower.starts_with("evidence gathered:")
            || lower.starts_with("evidence -")
            || lower.starts_with("evidence —")
            || lower.starts_with("evidence:");
        if !is_diagnostic_evidence {
            kept.push(trimmed);
        }
    }
    kept.join("\n\n")
}

fn strip_diagnostic_evidence_sections_clean(response: &str) -> String {
    let normalized = response.replace("\r\n", "\n");
    let mut kept = Vec::new();
    for paragraph in normalized.split("\n\n") {
        let trimmed = paragraph.trim();
        if trimmed.is_empty() {
            continue;
        }
        let lower = trimmed
            .replace(['\u{2014}', '\u{2013}'], "-")
            .to_ascii_lowercase();
        let is_diagnostic_evidence = lower.starts_with("evidence gathered:")
            || lower.starts_with("evidence -")
            || lower.starts_with("evidence:");
        if !is_diagnostic_evidence {
            kept.push(trimmed);
        }
    }
    kept.join("\n\n")
}

fn sanitize_final_user_response(response: &str) -> String {
    let stripped = strip_diagnostic_evidence_sections_clean(response);
    let trimmed = stripped.trim();
    if looks_like_raw_structured_tool_output(trimmed)
        || looks_like_raw_source_or_markup_dump(trimmed)
    {
        "I gathered raw tool output, but the final response formatting failed. Please retry the request."
            .to_string()
    } else {
        stripped
    }
}

fn sanitize_tool_loop_user_response(
    response: &str,
    batch: &tool_execution::ToolExecutionBatch,
    failure_note: &str,
) -> String {
    let stripped = strip_diagnostic_evidence_sections_clean(response);
    let trimmed = stripped.trim();
    if looks_like_raw_structured_tool_output(trimmed)
        || looks_like_raw_source_or_markup_dump(trimmed)
    {
        build_user_facing_tool_fallback_response(trimmed, batch, failure_note)
    } else {
        stripped
    }
}

fn normalize_watcher_notification_text(text: &str, watcher_description: &str) -> String {
    let trimmed = text.trim();
    if trimmed.is_empty() {
        return String::new();
    }

    let mut lines = trimmed.lines();
    let first_line = lines.next().unwrap_or_default().trim();
    let normalized_first_line = first_line
        .trim_matches('*')
        .trim_matches('#')
        .trim_matches(':')
        .trim();

    let body = if normalized_first_line.eq_ignore_ascii_case(watcher_description.trim()) {
        lines.collect::<Vec<_>>().join("\n")
    } else {
        trimmed.to_string()
    };

    body.trim().to_string()
}

fn watcher_notification_value_preview(value: &serde_json::Value) -> Option<String> {
    match value {
        serde_json::Value::Null => None,
        serde_json::Value::Bool(flag) => Some(flag.to_string()),
        serde_json::Value::Number(num) => Some(num.to_string()),
        serde_json::Value::String(text) => {
            let trimmed = text.trim();
            (!trimmed.is_empty()).then(|| safe_truncate(trimmed, 140))
        }
        serde_json::Value::Array(items) => (!items.is_empty()).then(|| {
            format!(
                "{} item{}",
                items.len(),
                if items.len() == 1 { "" } else { "s" }
            )
        }),
        serde_json::Value::Object(map) => (!map.is_empty()).then(|| {
            format!(
                "{} field{}",
                map.len(),
                if map.len() == 1 { "" } else { "s" }
            )
        }),
    }
}

fn fallback_watcher_notification_from_structured_payload(
    watcher: &super::watcher::Watcher,
    payload: &serde_json::Value,
    image_attached: bool,
) -> Option<String> {
    let object = payload.as_object()?;
    let mut lines = Vec::new();
    for (key, value) in object {
        if key.starts_with('_') {
            continue;
        }
        let Some(preview) = watcher_notification_value_preview(value) else {
            continue;
        };
        lines.push(format!("- {}: {}", key.replace('_', " "), preview));
        if lines.len() >= 5 {
            break;
        }
    }
    if lines.is_empty() {
        return None;
    }

    let headline = object
        .get("message")
        .or_else(|| object.get("summary"))
        .and_then(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| safe_truncate(value, 220))
        .unwrap_or_else(|| format!("Watcher matched: {}", watcher.description.trim()));

    let mut sections = vec![headline, lines.join("\n")];
    if image_attached {
        sections.push("A snapshot is attached.".to_string());
    }
    Some(sections.join("\n\n"))
}

fn fallback_watcher_notification_text(watcher: &super::watcher::Watcher, result: &str) -> String {
    let image_attached = watcher_result_output_files(result)
        .iter()
        .any(|path| watcher_output_file_is_image(path));
    if let Some(payload) = Agent::extract_structured_watcher_condition_payload(result) {
        if let Some(summary) =
            fallback_watcher_notification_from_structured_payload(watcher, &payload, image_attached)
        {
            return summary;
        }
    }

    let primary = automation_primary_result_text(result);
    let cleaned_result = primary
        .lines()
        .map(str::trim)
        .filter(|line| {
            !line.is_empty() && !line.starts_with("AgentArk auto-installed sandbox dependencies:")
        })
        .collect::<Vec<_>>()
        .join("\n");
    let result_text = cleaned_result.trim();
    if result_text.is_empty() {
        if image_attached {
            format!(
                "Watcher matched: {}\n\nA snapshot is attached.",
                watcher.description.trim()
            )
        } else {
            format!("Watcher matched: {}", watcher.description.trim())
        }
    } else {
        let mut message = format!(
            "Watcher matched: {}\n\n{}",
            watcher.description.trim(),
            result_text
        );
        if image_attached {
            message.push_str("\n\nA snapshot is attached.");
        }
        message
    }
}

#[derive(Debug, Clone)]
struct WatcherNotificationImage {
    web_path: String,
    filename: String,
    bytes: Vec<u8>,
}

fn watcher_notification_text_is_useful(text: &str) -> bool {
    let trimmed = text.trim();
    if trimmed.len() < 8 {
        return false;
    }
    let lower = trimmed.to_ascii_lowercase();
    if [
        "follow-up summary failed",
        "exhausted its eligible model chain",
        "raw result:",
        "final response could not be formatted",
        "gathered tool evidence",
        "traceback",
        "error executing",
    ]
    .iter()
    .any(|marker| lower.contains(marker))
    {
        return false;
    }
    if lower.starts_with("watcher matched:") && trimmed.contains('{') && trimmed.contains('}') {
        return false;
    }
    true
}

fn watcher_internal_match_text(
    watcher: &super::watcher::Watcher,
    result: &str,
    reason: &str,
) -> String {
    let primary = automation_primary_result_text(result);
    let cleaned = primary
        .lines()
        .map(str::trim)
        .filter(|line| {
            !line.is_empty() && !line.starts_with("AgentArk auto-installed sandbox dependencies:")
        })
        .take(8)
        .collect::<Vec<_>>()
        .join("\n");
    if cleaned.trim().is_empty() {
        format!(
            "Watcher matched: {}\n\nExternal notification suppressed: {}.",
            watcher.description.trim(),
            reason
        )
    } else {
        format!(
            "Watcher matched: {}\n\nExternal notification suppressed: {}.\n\nPoll result:\n{}",
            watcher.description.trim(),
            reason,
            cleaned
        )
    }
}

fn watcher_result_output_files(result: &str) -> Vec<String> {
    let parsed = serde_json::from_str::<serde_json::Value>(result)
        .ok()
        .or_else(|| extract_json_object_from_text(result));
    parsed
        .as_ref()
        .and_then(|value| value.get("files"))
        .and_then(|value| value.as_array())
        .map(|items| {
            items
                .iter()
                .filter_map(|item| item.as_str().map(str::trim))
                .filter(|item| !item.is_empty())
                .map(str::to_string)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default()
}

fn watcher_output_file_is_image(path: &str) -> bool {
    let lower = path.to_ascii_lowercase();
    matches!(
        lower.rsplit('.').next().unwrap_or_default(),
        "png" | "jpg" | "jpeg" | "gif" | "webp" | "bmp"
    )
}

fn parse_output_web_path(path: &str) -> Option<(String, String)> {
    let trimmed = path.trim();
    let rest = trimmed.strip_prefix("/api/outputs/")?;
    let mut parts = rest.splitn(2, '/');
    let exec_id = parts.next()?.trim();
    let filename = parts.next()?.trim();
    if uuid::Uuid::parse_str(exec_id).is_err()
        || filename.is_empty()
        || filename.contains('/')
        || filename.contains('\\')
        || filename.contains("..")
    {
        return None;
    }
    Some((exec_id.to_string(), filename.to_string()))
}

fn normalize_automation_notification_channel(value: Option<&str>) -> String {
    match value
        .map(str::trim)
        .filter(|raw| !raw.is_empty())
        .map(|raw| raw.to_ascii_lowercase())
    {
        Some(channel) if channel == "push" => "preferred".to_string(),
        Some(channel)
            if matches!(
                channel.as_str(),
                "app" | "app_notification" | "app_notifications" | "in_app"
            ) =>
        {
            String::new()
        }
        Some(channel) if matches!(channel.as_str(), "auto" | "default") => "preferred".to_string(),
        Some(channel) => channel,
        None => "preferred".to_string(),
    }
}

const PUSH_NOTIFICATION_CHANNELS: &[&str] = &[
    "telegram",
    "whatsapp",
    "slack",
    "discord",
    "matrix",
    "teams",
    "google_chat",
    "signal",
    "imessage",
    "line",
    "wechat",
    "qq",
];

fn watcher_delivery_label(notify_channel: &str) -> String {
    let normalized = notify_channel.trim().to_ascii_lowercase();
    if normalized.is_empty() {
        "In-app notification only".to_string()
    } else if normalized == "preferred" {
        "Preferred notification channel when connected, otherwise in-app".to_string()
    } else if is_external_notification_channel(&normalized) {
        notification_channel_display_name(&normalized).to_string()
    } else {
        normalized
    }
}

