fn background_session_policy_for_action(
    all_actions: &[crate::actions::ActionDef],
    action_name: &str,
) -> super::background_session::BackgroundSessionPolicy {
    let meta = all_actions
        .iter()
        .find(|action| action.name.eq_ignore_ascii_case(action_name.trim()))
        .map(crate::actions::ActionDef::planner_metadata)
        .unwrap_or_default();
    super::background_session::BackgroundSessionPolicy {
        allowed_action_roles: vec![planner_action_role_name(&meta.role).to_string()],
        allowed_integration_classes: vec![
            planner_integration_class_name(&meta.integration_class).to_string()
        ],
    }
    .normalized()
}

fn is_push_notification_channel(channel: &str) -> bool {
    PUSH_NOTIFICATION_CHANNELS
        .iter()
        .any(|candidate| candidate.eq_ignore_ascii_case(channel.trim()))
}

fn is_external_notification_channel(channel: &str) -> bool {
    let trimmed = channel.trim().to_ascii_lowercase();
    // Namespaced pack channel ids (see
    // `crate::channels::messaging_registry::EXTENSION_CHANNEL_ID_PREFIX`) are
    // structurally valid external channels even though they aren't in the
    // bundled compile-time list. The registry is the authoritative source of
    // truth for whether the id is actually installed and configured; this
    // function answers the narrower question "is this a well-shaped external
    // channel id?" without reaching into async registry state.
    if trimmed.starts_with(crate::channels::messaging_registry::EXTENSION_CHANNEL_ID_PREFIX)
        || trimmed.starts_with(crate::custom_messaging_channels::CUSTOM_CHANNEL_ID_PREFIX)
    {
        return true;
    }
    crate::channels::messaging_registry::BUNDLED_CHANNEL_IDS
        .iter()
        .any(|candidate| candidate.eq_ignore_ascii_case(&trimmed))
}

fn notification_channel_display_name(channel: &str) -> &str {
    match channel.trim().to_ascii_lowercase().as_str() {
        "web" => "local Web UI",
        "email" => "Email",
        "google_chat" => "Google Chat",
        "signal" => "Signal",
        "imessage" => "iMessage",
        "line" => "LINE",
        "wechat" => "WeChat",
        "qq" => "QQ",
        "telegram" => "Telegram",
        "whatsapp" => "WhatsApp",
        "slack" => "Slack",
        "discord" => "Discord",
        "matrix" => "Matrix",
        "teams" => "Teams",
        _ => channel,
    }
}

fn inbound_security_source_label(channel: &str) -> String {
    notification_channel_display_name(channel).to_string()
}

fn telegram_notification_target_is_configured(
    config: &crate::core::config::TelegramConfig,
) -> bool {
    !config.bot_token.trim().is_empty()
        && config.allowed_users.len() == 1
        && config.allowed_users.first().copied().unwrap_or_default() != 0
}

fn whatsapp_notification_target_is_configured(
    config: &crate::channels::whatsapp::WhatsAppChannelConfig,
) -> bool {
    let has_target = crate::channels::whatsapp::configured_notification_recipient(config).is_some();
    match config.mode {
        crate::channels::whatsapp::WhatsAppMode::CloudApi => {
            !config.access_token.trim().is_empty()
                && !config.phone_number_id.trim().is_empty()
                && has_target
        }
        crate::channels::whatsapp::WhatsAppMode::Baileys => {
            !config.bridge_url.trim().is_empty() && has_target
        }
    }
}

fn sanitize_integration_class_list(values: &[String]) -> Vec<String> {
    let allowed = [
        "internal",
        "messaging",
        "workspace",
        "search",
        "browser",
        "filesystem",
        "app",
        "code",
        "network",
        "commerce",
        "analytics",
        "media",
    ];
    let mut seen = HashSet::new();
    let mut cleaned = Vec::new();
    for value in values {
        let normalized = value.trim().to_ascii_lowercase();
        if normalized.is_empty()
            || !allowed.contains(&normalized.as_str())
            || !seen.insert(normalized.clone())
        {
            continue;
        }
        cleaned.push(normalized);
    }
    cleaned
}

fn automation_notification_message_from_text(
    task_desc: &str,
    action_arguments: &serde_json::Value,
) -> String {
    if let Some(message) = action_arguments
        .get("message")
        .and_then(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        return message.to_string();
    }

    let trimmed = task_desc.trim();
    if trimmed.is_empty() {
        return "Reminder".to_string();
    }

    let lower = trimmed.to_ascii_lowercase();
    for prefix in [
        "notify user:",
        "notify me:",
        "message me:",
        "message user:",
        "alert me:",
        "tell me:",
        "ping me:",
    ] {
        if lower.starts_with(prefix) {
            let candidate = trimmed[prefix.len()..].trim();
            if !candidate.is_empty() {
                return candidate.to_string();
            }
        }
    }

    for prefix in [
        "remind me to ",
        "remind me ",
        "notify me when ",
        "tell me when ",
    ] {
        if lower.starts_with(prefix) {
            let candidate = trimmed[prefix.len()..].trim();
            if !candidate.is_empty() {
                return format!("Reminder: {}", candidate);
            }
        }
    }

    format!("Reminder: {}", trimmed.trim_end_matches(['.', '!', '?']))
}

fn schedule_action_is_internal_notification(action_name: &str) -> bool {
    matches!(
        action_name.trim().to_ascii_lowercase().as_str(),
        "notify_user" | "goal_reminder" | "goal_progress_report" | "daily_brief"
    )
}

fn build_notify_user_action_arguments(
    existing_arguments: &serde_json::Value,
    task_desc: &str,
    delivery_channel: &str,
) -> serde_json::Value {
    let mut payload = existing_arguments.as_object().cloned().unwrap_or_default();
    payload.remove("query");
    payload.insert(
        "message".to_string(),
        serde_json::Value::String(automation_notification_message_from_text(
            task_desc,
            existing_arguments,
        )),
    );
    if delivery_channel.trim().is_empty() {
        payload.remove("report_to");
    } else {
        payload.insert(
            "report_to".to_string(),
            serde_json::Value::String(delivery_channel.trim().to_ascii_lowercase()),
        );
    }
    serde_json::Value::Object(payload)
}

fn schedule_task_should_default_to_notify_user(
    task_desc: &str,
    explicit_action: Option<&str>,
    scheduled_for: Option<chrono::DateTime<chrono::Utc>>,
    existing_arguments: &serde_json::Value,
) -> bool {
    if scheduled_for.is_none() {
        return false;
    }
    if explicit_action
        .map(str::trim)
        .is_some_and(|value| !value.is_empty())
    {
        return false;
    }

    if let Some(arguments) = existing_arguments.as_object() {
        let has_non_notification_keys = arguments.keys().any(|key| {
            !matches!(
                key.as_str(),
                "query" | "report_to" | "title" | "message" | "_automation"
            )
        });
        if has_non_notification_keys {
            return false;
        }
    }

    let normalized = task_desc.trim().to_ascii_lowercase();
    if normalized.is_empty() {
        return false;
    }
    if [
        "remind",
        "notify",
        "meeting",
        "appointment",
        "birthday",
        "anniversary",
        "interview",
        "doctor",
        "dentist",
        "reservation",
        "flight",
        "train",
        "call with",
    ]
    .iter()
    .any(|token| normalized.contains(token))
    {
        return true;
    }

    let words = normalized
        .split_whitespace()
        .map(|word| {
            word.trim_matches(|ch: char| !ch.is_ascii_alphanumeric() && ch != '\'' && ch != '-')
        })
        .filter(|word| !word.is_empty())
        .collect::<Vec<_>>();
    if words.is_empty() || words.len() > 8 {
        return false;
    }

    let first = words[0];
    if matches!(
        first,
        "run"
            | "generate"
            | "create"
            | "send"
            | "check"
            | "scan"
            | "sync"
            | "backup"
            | "deploy"
            | "research"
            | "review"
            | "summarize"
            | "fetch"
            | "refresh"
            | "update"
            | "call"
            | "email"
            | "draft"
            | "write"
    ) {
        return false;
    }

    true
}

const CALENDAR_AGENTARK_REMINDER_FIELD: &str = "agentark_reminder";
const DEFAULT_CALENDAR_AGENTARK_REMINDER_MINUTES: i64 = 15;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CalendarAgentArkReminderMode {
    CreatedCalendarEvent,
    CalendarWriteFallback,
}

#[derive(Debug, Clone, Deserialize)]
struct AgentArkReminderExtractionPayload {
    #[serde(default)]
    reminders: Vec<AgentArkReminderExtractionItem>,
}

#[derive(Debug, Clone, Deserialize)]
struct AgentArkReminderExtractionItem {
    task: Option<String>,
    at: Option<String>,
    title: Option<String>,
    message: Option<String>,
}

fn agentark_reminder_tool_call(
    task: String,
    at: chrono::DateTime<chrono::Utc>,
    title: String,
    message: String,
    allow_duplicate: bool,
) -> crate::core::llm::ToolCall {
    crate::core::llm::ToolCall {
        id: format!("agentark_reminder_{}", uuid::Uuid::new_v4()),
        name: "schedule_task".to_string(),
        arguments: serde_json::json!({
            "task": task,
            "at": at.to_rfc3339(),
            "action": "notify_user",
            "action_arguments": {
                "title": title,
                "message": message,
                "report_to": "push"
            },
            "report_to": "push",
            "allow_duplicate": allow_duplicate,
            "automation_policy": {
                "max_attempts": 1,
                "validation": { "mode": "non_empty_result" }
            }
        }),
    }
}

fn schedule_task_reminder_signature(call: &crate::core::llm::ToolCall) -> Option<String> {
    if !call.name.eq_ignore_ascii_case("schedule_task") {
        return None;
    }
    let task = call
        .arguments
        .get("task")
        .and_then(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())?;
    let at = call
        .arguments
        .get("at")
        .and_then(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())?;
    Some(format!("{}|{}", task.to_ascii_lowercase(), at))
}

fn calendar_agentark_reminder_enabled(arguments: &serde_json::Value) -> bool {
    let Some(value) = arguments.get(CALENDAR_AGENTARK_REMINDER_FIELD) else {
        return true;
    };
    if let Some(enabled) = value.as_bool() {
        return enabled;
    }
    value
        .as_object()
        .and_then(|object| object.get("enabled"))
        .and_then(|enabled| enabled.as_bool())
        .unwrap_or(true)
}

fn calendar_agentark_reminder_minutes(arguments: &serde_json::Value) -> i64 {
    arguments
        .get(CALENDAR_AGENTARK_REMINDER_FIELD)
        .and_then(|value| value.as_object())
        .and_then(|object| object.get("minutes_before"))
        .and_then(|value| value.as_i64())
        .unwrap_or(DEFAULT_CALENDAR_AGENTARK_REMINDER_MINUTES)
        .clamp(1, 24 * 60)
}

fn local_naive_datetime_to_utc(
    naive: chrono::NaiveDateTime,
    tz: Option<chrono_tz::Tz>,
) -> Option<chrono::DateTime<chrono::Utc>> {
    use chrono::TimeZone;

    match tz.unwrap_or(chrono_tz::UTC).from_local_datetime(&naive) {
        chrono::LocalResult::Single(value) => Some(value.with_timezone(&chrono::Utc)),
        chrono::LocalResult::Ambiguous(early, _) => Some(early.with_timezone(&chrono::Utc)),
        chrono::LocalResult::None => None,
    }
}

fn parse_agentark_calendar_datetime(
    value: &str,
    tz: Option<chrono_tz::Tz>,
) -> Option<chrono::DateTime<chrono::Utc>> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        return None;
    }
    if let Ok(value) = chrono::DateTime::parse_from_rfc3339(trimmed) {
        return Some(value.with_timezone(&chrono::Utc));
    }
    if let Ok(value) = chrono::NaiveDateTime::parse_from_str(trimmed, "%Y-%m-%dT%H:%M:%S") {
        return local_naive_datetime_to_utc(value, tz);
    }
    if let Ok(value) = chrono::NaiveDateTime::parse_from_str(trimmed, "%Y-%m-%dT%H:%M") {
        return local_naive_datetime_to_utc(value, tz);
    }
    None
}

fn parse_agentark_request_reminder_datetime(
    value: &str,
    tz: Option<chrono_tz::Tz>,
) -> Option<chrono::DateTime<chrono::Utc>> {
    let normalized = value.trim().trim_end_matches('.').replace(',', "");
    if normalized.is_empty() {
        return None;
    }
    if let Some(parsed) = parse_agentark_calendar_datetime(&normalized, tz) {
        return Some(parsed);
    }

    for format in [
        "%d %B %Y %I:%M %p",
        "%d %B %Y %I %p",
        "%d %B %Y %H:%M",
        "%d %b %Y %I:%M %p",
        "%d %b %Y %I %p",
        "%d %b %Y %H:%M",
    ] {
        if let Ok(value) = chrono::NaiveDateTime::parse_from_str(&normalized, format) {
            if let Some(parsed) = local_naive_datetime_to_utc(value, tz) {
                return Some(parsed);
            }
        }
    }

    for format in ["%d %B %Y", "%d %b %Y"] {
        if let Ok(date) = chrono::NaiveDate::parse_from_str(&normalized, format) {
            if let Some(value) = date.and_hms_opt(9, 0, 0) {
                if let Some(parsed) = local_naive_datetime_to_utc(value, tz) {
                    return Some(parsed);
                }
            }
        }
    }

    None
}

fn extract_line_based_agentark_reminder_calls(
    request_text: &str,
    tz: Option<chrono_tz::Tz>,
    existing_reminders: &[crate::core::llm::ToolCall],
) -> Vec<crate::core::llm::ToolCall> {
    let mut seen = existing_reminders
        .iter()
        .filter_map(schedule_task_reminder_signature)
        .collect::<HashSet<_>>();
    let mut reminders = Vec::new();

    for raw_line in request_text.lines() {
        let trimmed = raw_line
            .trim()
            .trim_start_matches(|ch: char| matches!(ch, '-' | '*' | ' ' | '\t' | '\u{2022}'))
            .trim();
        let Some((label, when)) = trimmed.split_once(':') else {
            continue;
        };
        let label = label.trim();
        if label.is_empty() {
            continue;
        }
        let Some(at) = parse_agentark_request_reminder_datetime(when, tz) else {
            continue;
        };
        if at <= chrono::Utc::now() {
            continue;
        }
        let call = agentark_reminder_tool_call(
            format!("Notify user: {} is today!", label),
            at,
            format!("Reminder: {}", label),
            format!("{} is today.", label),
            false,
        );
        let Some(signature) = schedule_task_reminder_signature(&call) else {
            continue;
        };
        if seen.insert(signature) {
            reminders.push(call);
        }
    }

    reminders
}

fn calendar_write_failure_allows_agentark_reminder_fallback(
    batch: &tool_execution::ToolExecutionBatch,
    index: usize,
) -> bool {
    let outcome_text = batch
        .outcomes
        .get(index)
        .map(|outcome| {
            [
                outcome.content.as_str(),
                outcome.error.as_deref().unwrap_or_default(),
            ]
            .join(" ")
        })
        .unwrap_or_default();
    let output_text = batch
        .outputs
        .get(index)
        .map(|output| output.content.as_str())
        .unwrap_or_default();
    let combined = [outcome_text.as_str(), output_text].join(" ");
    response_indicates_permission_requirement(&combined)
        || response_indicates_credentials_requirement(&combined)
        || response_indicates_integration_requirement(&combined)
}

fn calendar_create_agentark_reminder_calls_for_timezone(
    tool_calls: &[crate::core::llm::ToolCall],
    prior_tool_calls: &[crate::core::llm::ToolCall],
    batch: &tool_execution::ToolExecutionBatch,
    tz: Option<chrono_tz::Tz>,
) -> Vec<crate::core::llm::ToolCall> {
    calendar_create_agentark_reminder_calls_with_mode(
        tool_calls,
        prior_tool_calls,
        batch,
        tz,
        CalendarAgentArkReminderMode::CreatedCalendarEvent,
    )
}

fn calendar_create_agentark_reminder_fallback_calls_for_timezone(
    tool_calls: &[crate::core::llm::ToolCall],
    prior_tool_calls: &[crate::core::llm::ToolCall],
    batch: &tool_execution::ToolExecutionBatch,
    tz: Option<chrono_tz::Tz>,
) -> Vec<crate::core::llm::ToolCall> {
    calendar_create_agentark_reminder_calls_with_mode(
        tool_calls,
        prior_tool_calls,
        batch,
        tz,
        CalendarAgentArkReminderMode::CalendarWriteFallback,
    )
}

fn calendar_create_agentark_reminder_calls_with_mode(
    tool_calls: &[crate::core::llm::ToolCall],
    prior_tool_calls: &[crate::core::llm::ToolCall],
    batch: &tool_execution::ToolExecutionBatch,
    tz: Option<chrono_tz::Tz>,
    mode: CalendarAgentArkReminderMode,
) -> Vec<crate::core::llm::ToolCall> {
    let fallback_batch_needs_setup =
        matches!(mode, CalendarAgentArkReminderMode::CalendarWriteFallback)
            && (tool_batch_indicates_permission_requirement(batch)
                || tool_batch_indicates_credentials_requirement(batch)
                || tool_batch_indicates_integration_requirement(batch));
    let mut reminders = Vec::new();
    let mut seen_reminders = prior_tool_calls
        .iter()
        .chain(tool_calls.iter())
        .filter_map(schedule_task_reminder_signature)
        .collect::<HashSet<_>>();
    for (index, call) in tool_calls.iter().enumerate() {
        if !call.name.eq_ignore_ascii_case("calendar_create") {
            continue;
        }
        let should_schedule = match mode {
            CalendarAgentArkReminderMode::CreatedCalendarEvent => {
                tool_batch_output_succeeded(batch, index)
            }
            CalendarAgentArkReminderMode::CalendarWriteFallback => {
                (tool_batch_output_failed(batch, index)
                    && calendar_write_failure_allows_agentark_reminder_fallback(batch, index))
                    || (fallback_batch_needs_setup && index >= batch.outputs.len())
            }
        };
        if !should_schedule {
            continue;
        }
        if !calendar_agentark_reminder_enabled(&call.arguments) {
            continue;
        }

        let Some(start) = call
            .arguments
            .get("start")
            .and_then(|value| value.as_str())
            .and_then(|value| parse_agentark_calendar_datetime(value, tz))
        else {
            continue;
        };
        let event_start = start;
        let minutes_before = calendar_agentark_reminder_minutes(&call.arguments);
        let reminder_at = match mode {
            CalendarAgentArkReminderMode::CreatedCalendarEvent => {
                event_start - chrono::Duration::minutes(minutes_before)
            }
            CalendarAgentArkReminderMode::CalendarWriteFallback => event_start,
        };
        if reminder_at <= chrono::Utc::now() {
            continue;
        }

        let summary = call
            .arguments
            .get("summary")
            .and_then(|value| value.as_str())
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .unwrap_or("Calendar event");
        let (task, title, message) = match mode {
            CalendarAgentArkReminderMode::CreatedCalendarEvent => (
                format!("Reminder for calendar event: {}", summary),
                "Upcoming meeting".to_string(),
                format!(
                    "{} starts in {} minute{}.",
                    summary,
                    minutes_before,
                    if minutes_before == 1 { "" } else { "s" }
                ),
            ),
            CalendarAgentArkReminderMode::CalendarWriteFallback => (
                format!("Reminder for event: {}", summary),
                "Event reminder".to_string(),
                format!("{} is due now.", summary),
            ),
        };
        let reminder = agentark_reminder_tool_call(task, reminder_at, title, message, false);
        if let Some(signature) = schedule_task_reminder_signature(&reminder) {
            if seen_reminders.insert(signature) {
                reminders.push(reminder);
            }
        }
    }

    reminders
}

fn build_current_time_action_arguments(
    existing_arguments: &serde_json::Value,
    timezone: Option<&str>,
) -> serde_json::Value {
    let mut payload = serde_json::Map::new();
    let timezone_value = existing_arguments
        .get("timezone")
        .and_then(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .or(timezone.map(str::trim).filter(|value| !value.is_empty()));
    if let Some(timezone_value) = timezone_value {
        payload.insert(
            "timezone".to_string(),
            serde_json::Value::String(timezone_value.to_string()),
        );
    }
    serde_json::Value::Object(payload)
}

fn extract_model_failure_tool_name(error: &str) -> Option<String> {
    for marker in ["function '", "function \"", "tool '", "tool \""] {
        let Some(start) = error.find(marker) else {
            continue;
        };
        let rest = &error[start + marker.len()..];
        let terminator = if marker.ends_with('\'') { '\'' } else { '"' };
        if let Some(end) = rest.find(terminator) {
            let name = rest[..end].trim();
            if !name.is_empty() {
                return Some(name.to_string());
            }
        }
    }
    None
}

fn summarize_model_failure_for_user(error: &str) -> String {
    let trimmed = error.trim();
    if trimmed.is_empty() {
        return "A configured model failed unexpectedly.".to_string();
    }

    let (label, detail) = match trimmed.split_once(" failed: ") {
        Some((head, tail)) if !head.trim().is_empty() => (Some(head.trim()), tail.trim()),
        _ => (None, trimmed),
    };
    let lower = detail.to_ascii_lowercase();
    let prefix = label
        .map(|value| format!("{}: ", value))
        .unwrap_or_default();

    if lower.contains("invalid schema for function")
        || lower.contains("invalid_function_parameters")
    {
        let tool_name = extract_model_failure_tool_name(detail)
            .unwrap_or_else(|| "a framework tool".to_string());
        return format!(
            "{}rejected the current tool schema for `{}`.",
            prefix, tool_name
        );
    }
    if lower.contains("timed out") {
        return format!("{}timed out before responding.", prefix);
    }
    if (lower.contains("localhost:11434")
        || lower.contains("127.0.0.1:11434")
        || lower.contains("/api/chat"))
        && (lower.contains("error sending request for url")
            || lower.contains("connection refused")
            || lower.contains("connection reset")
            || lower.contains("transport"))
    {
        return format!(
            "{}could not reach the configured local model service.",
            prefix
        );
    }
    if lower.contains("dns error")
        || lower.contains("no such host")
        || lower.contains("name or service not known")
    {
        return format!(
            "{}could not reach the configured provider endpoint.",
            prefix
        );
    }
    if lower.contains("rate limit") || lower.contains("rate-limit") || lower.contains("429") {
        return format!("{}was rate-limited by the provider.", prefix);
    }
    if lower.contains("context length")
        || lower.contains("maximum context")
        || lower.contains("too many tokens")
    {
        return format!(
            "{}rejected the request because the context was too large.",
            prefix
        );
    }
    if lower.contains("provider returned error")
        || lower.contains("api error")
        || lower.contains("bad request")
    {
        return format!("{}returned an upstream provider error.", prefix);
    }

    format!("{}failed: {}.", prefix, safe_truncate(detail, 160))
}

fn build_tool_followup_model_failure_note(error: &str) -> String {
    let summary = summarize_model_failure_for_user(error);
    format!(
        "I completed the latest tool step, but the follow-up model failed before it could choose the next step or finish the answer. {} The run is checkpointed for resume. Here is the latest tool-backed status.",
        summary
    )
}

fn build_tool_followup_model_chain_failure_note(errors: &[String], timed_out_only: bool) -> String {
    if errors.is_empty() {
        return if timed_out_only {
            "I completed the latest tool step, but the follow-up models timed out before they could choose the next step or finish the answer. The run is checkpointed for resume. Here is the latest tool-backed status.".to_string()
        } else {
            "I completed the latest tool step, but the follow-up model chain failed before it could choose the next step or finish the answer. The run is checkpointed for resume. Here is the latest tool-backed status.".to_string()
        };
    }
    let summary = summarize_model_failures_for_user(errors);
    if timed_out_only {
        format!(
            "I completed the latest tool step, but the follow-up models timed out before they could choose the next step or finish the answer. {} The run is checkpointed for resume. Here is the latest tool-backed status.",
            summary
        )
    } else if errors.len() > 1 {
        format!(
            "I completed the latest tool step, but the follow-up model chain failed before it could choose the next step or finish the answer. {} The run is checkpointed for resume. Here is the latest tool-backed status.",
            summary
        )
    } else {
        build_tool_followup_model_failure_note(&errors[0])
    }
}

fn tool_followup_failure_degradation_note(
    errors: &[String],
    timed_out_only: bool,
) -> crate::core::DegradationNote {
    crate::core::DegradationNote {
        kind: "model_followup".to_string(),
        summary: if timed_out_only {
            "follow-up model timed out before selecting the next step".to_string()
        } else {
            "follow-up model failed before selecting the next step".to_string()
        },
        detail: if errors.is_empty() {
            None
        } else {
            Some(safe_truncate(&errors.join(" | "), 800))
        },
    }
}

fn reconcile_tool_degradation_notes(
    degradation_notes: &mut Vec<crate::core::DegradationNote>,
    cumulative_tool_batch: &tool_execution::ToolExecutionBatch,
) {
    let mut tools_with_prior_non_success = HashSet::new();
    let mut recovered_tools = HashSet::new();

    for outcome in &cumulative_tool_batch.outcomes {
        let tool_name = outcome.name.trim().to_ascii_lowercase();
        if tool_name.is_empty() {
            continue;
        }

        match outcome.status {
            crate::core::ToolOutcomeStatus::Success => {
                if tools_with_prior_non_success.contains(&tool_name) {
                    recovered_tools.insert(tool_name);
                }
            }
            _ => {
                tools_with_prior_non_success.insert(tool_name);
            }
        }
    }

    if !recovered_tools.is_empty() {
        degradation_notes.retain(|note| {
            if note.kind != "tool" {
                return true;
            }
            let summary = note.summary.trim().to_ascii_lowercase();
            !recovered_tools
                .iter()
                .any(|tool_name| summary.starts_with(&format!("{tool_name}: ")))
        });
    }

    let mut seen = HashSet::new();
    degradation_notes
        .retain(|note| seen.insert((note.kind.clone(), note.summary.clone(), note.detail.clone())));
}

fn summarize_model_failures_for_user(errors: &[String]) -> String {
    let mut summaries = Vec::new();
    let mut seen = HashSet::new();
    for error in errors {
        let summary = summarize_model_failure_for_user(error);
        if seen.insert(summary.clone()) {
            summaries.push(summary);
        }
        if summaries.len() >= 3 {
            break;
        }
    }
    summaries.join(" ")
}

fn build_llm_phase_failure_response(
    phase_label: &str,
    provider_name: &str,
    model_name: &str,
    failure_detail: &str,
) -> String {
    let phase = phase_label.trim();
    let detail = failure_detail.trim().trim_end_matches('.');
    let detail_line = if detail.is_empty() {
        "Failure: the provider did not return a usable response.".to_string()
    } else {
        format!("Failure: {}.", safe_truncate(detail, 220))
    };
    format!(
        "I couldn't continue because the LLM failed during {}.\n\nProvider: {}\nModel: {}\n{}\n\nPlease retry after the model backend is healthy.",
        if phase.is_empty() {
            "this request"
        } else {
            phase
        },
        provider_name.trim(),
        model_name.trim(),
        detail_line
    )
}

fn legacy_llm_is_unconfigured_placeholder(config: &AgentConfig) -> bool {
    config.model_pool.slots.is_empty()
        && config.llm_fallback.is_none()
        && matches!(
            &config.llm,
            LlmProvider::Ollama { base_url, model }
                if model.trim().is_empty() && base_url.trim().is_empty()
        )
}

fn legacy_llm_is_explicitly_configured(config: &AgentConfig) -> bool {
    if config.model_pool.slots.is_empty() && config.llm_fallback.is_none() {
        match &config.llm {
            LlmProvider::Ollama { base_url, model } => {
                !base_url.trim().is_empty() && !model.trim().is_empty()
            }
            LlmProvider::Anthropic { api_key, model } => {
                !api_key.trim().is_empty() && !model.trim().is_empty()
            }
            LlmProvider::OpenAI {
                api_key,
                model,
                base_url,
            } => {
                !api_key.trim().is_empty()
                    && !model.trim().is_empty()
                    && (base_url.is_none()
                        || base_url.as_ref().is_some_and(|url| !url.trim().is_empty()))
            }
        }
    } else {
        false
    }
}

fn llm_provider_is_structurally_configured(provider: &LlmProvider) -> bool {
    match provider {
        LlmProvider::Ollama { base_url, model } => {
            !base_url.trim().is_empty() && !model.trim().is_empty()
        }
        LlmProvider::Anthropic { api_key, model } => {
            !api_key.trim().is_empty() && !model.trim().is_empty()
        }
        LlmProvider::OpenAI {
            api_key,
            model,
            base_url,
        } => {
            if model.trim().is_empty() {
                return false;
            }
            match crate::core::llm_provider::openai_provider_label(base_url.as_deref()) {
                "openai" => !api_key.trim().is_empty(),
                "openrouter" | "openai-subscription" | "huggingface" => {
                    !api_key.trim().is_empty()
                        && base_url.as_ref().is_some_and(|url| !url.trim().is_empty())
                }
                "openai-compatible" => base_url.as_ref().is_some_and(|url| !url.trim().is_empty()),
                _ => false,
            }
        }
    }
}

fn model_pool_slot_is_configured(slot: &ModelSlot) -> bool {
    slot.enabled && llm_provider_is_structurally_configured(&slot.provider)
}

pub(crate) fn chat_model_is_configured(config: &AgentConfig) -> bool {
    if !config.model_pool.slots.is_empty() {
        return config
            .model_pool
            .slots
            .iter()
            .any(model_pool_slot_is_configured);
    }

    !legacy_llm_is_unconfigured_placeholder(config) && legacy_llm_is_explicitly_configured(config)
}

fn enrich_supervisor_outcome_with_model_failures(outcome: &mut crate::core::UserFacingOutcome) {
    let errors: Vec<String> = outcome
        .attempted_models
        .iter()
        .filter(|attempt| !attempt.success)
        .filter_map(|attempt| attempt.error.clone())
        .collect();
    let summary = summarize_model_failures_for_user(&errors);
    if summary.is_empty() || outcome.message.contains(&summary) {
        return;
    }
    outcome.message = format!(
        "{}\n\nRecent model failures: {}",
        outcome.message.trim(),
        summary
    );
}

fn response_indicates_pending_execution(text: &str) -> bool {
    let lower = text.trim().to_ascii_lowercase();
    if lower.is_empty() {
        return false;
    }
    let promise_markers = [
        "i'll ",
        "i will ",
        "let me ",
        "now i need to ",
        "next i ",
        "the next step",
    ];
    let action_markers = [
        "inspect", "read", "write", "update", "edit", "fix", "patch", "test", "verify", "deploy",
        "redeploy", "restart", "validate",
    ];
    promise_markers.iter().any(|marker| lower.contains(marker))
        && action_markers.iter().any(|marker| lower.contains(marker))
}

fn response_indicates_permission_requirement(text: &str) -> bool {
    let lower = text.trim().to_ascii_lowercase();
    if lower.is_empty() {
        return false;
    }
    [
        "blocked by saved user rule",
        "blocked by safety policy",
        "explicit approval",
        "requires approval",
        "approval required",
        "awaiting approval",
        "before any side-effecting action",
    ]
    .iter()
    .any(|marker| lower.contains(marker))
}

fn response_contains_browser_handoff_reference(text: &str) -> bool {
    let trimmed = text.trim();
    !trimmed.is_empty() && trimmed.contains("/ui/browser-handoff/")
}

fn content_reports_browser_auto_session_started(content: &str) -> bool {
    let Ok(payload) = serde_json::from_str::<serde_json::Value>(content.trim()) else {
        return false;
    };
    payload.get("status").and_then(|value| value.as_str()) == Some("session_started")
        && payload
            .get("session_id")
            .and_then(|value| value.as_str())
            .is_some_and(|value| !value.trim().is_empty())
}

fn tool_result_is_browser_handoff(name: &str, content: &str) -> bool {
    response_contains_browser_handoff_reference(content)
        || (name.eq_ignore_ascii_case("browser_auto")
            && content_reports_browser_auto_session_started(content))
}

fn response_indicates_credentials_requirement(text: &str) -> bool {
    let trimmed = text.trim();
    if trimmed.is_empty() {
        return false;
    }
    if response_contains_browser_handoff_reference(text) {
        return false;
    }
    if let Some(payload) = parse_workflow_missing_inputs_marker(trimmed) {
        return !payload.sensitive_missing.is_empty();
    }
    let Ok(payload) = serde_json::from_str::<serde_json::Value>(trimmed) else {
        return false;
    };
    if payload
        .get("status")
        .and_then(|value| value.as_str())
        .is_some_and(|value| value.trim().eq_ignore_ascii_case("needs_credentials"))
    {
        return true;
    }
    if payload
        .pointer("/user_outcome/request_state")
        .and_then(|value| value.as_str())
        .is_some_and(|value| value.trim().eq_ignore_ascii_case("needs_credentials"))
    {
        return true;
    }
    if payload
        .get("required_secrets")
        .and_then(|value| value.as_array())
        .is_some_and(|items| {
            items
                .iter()
                .any(|item| item.as_str().is_some_and(|value| !value.trim().is_empty()))
        })
    {
        return true;
    }
    false
}

fn response_indicates_integration_requirement(text: &str) -> bool {
    let lower = text.trim().to_ascii_lowercase();
    if lower.is_empty() {
        return false;
    }
    lower.contains("needs auth")
        || lower.contains("not configured")
        || lower.contains("integration is disabled")
        || lower.contains("connect an integration")
        || (lower.contains("integration")
            && ["connect", "configure", "enable", "setup", "set up"]
                .iter()
                .any(|marker| lower.contains(marker)))
}

fn tool_batch_indicates_permission_requirement(batch: &tool_execution::ToolExecutionBatch) -> bool {
    batch.outcomes.iter().any(|outcome| {
        matches!(
            outcome.status,
            crate::core::ToolOutcomeStatus::Blocked | crate::core::ToolOutcomeStatus::NeedsInput
        ) && response_indicates_permission_requirement(&outcome.content)
    }) || batch
        .outputs
        .iter()
        .any(|output| response_indicates_permission_requirement(&output.content))
}

fn tool_batch_indicates_credentials_requirement(
    batch: &tool_execution::ToolExecutionBatch,
) -> bool {
    batch.outcomes.iter().any(|outcome| {
        if tool_result_is_browser_handoff(&outcome.name, &outcome.content) {
            return false;
        }
        matches!(outcome.status, crate::core::ToolOutcomeStatus::NeedsInput)
            && response_indicates_credentials_requirement(&outcome.content)
    }) || batch.outputs.iter().any(|output| {
        !tool_result_is_browser_handoff(&output.name, &output.content)
            && response_indicates_credentials_requirement(&output.content)
    })
}

fn tool_batch_indicates_integration_requirement(
    batch: &tool_execution::ToolExecutionBatch,
) -> bool {
    batch.outcomes.iter().any(|outcome| {
        matches!(
            outcome.status,
            crate::core::ToolOutcomeStatus::NeedsInput
                | crate::core::ToolOutcomeStatus::RecoverableError
                | crate::core::ToolOutcomeStatus::Blocked
        ) && response_indicates_integration_requirement(&outcome.content)
    }) || batch
        .outputs
        .iter()
        .any(|output| response_indicates_integration_requirement(&output.content))
}

fn tool_batch_has_successful_persistent_artifact(
    batch: &tool_execution::ToolExecutionBatch,
) -> bool {
    batch.outputs.iter().enumerate().any(|(index, output)| {
        if !tool_batch_output_succeeded(batch, index) {
            return false;
        }
        let inferred_action = crate::actions::ActionDef {
            name: output.name.clone(),
            description: String::new(),
            version: "0".to_string(),
            input_schema: serde_json::json!({}),
            capabilities: Vec::new(),
            sandbox_mode: None,
            source: crate::actions::ActionSource::System,
            file_path: None,
            authorization: Default::default(),
        };
        let metadata = inferred_action.planner_metadata();
        let content_lower = output.content.to_ascii_lowercase();
        matches!(metadata.role, PlannerActionRole::Orchestration)
            || (matches!(metadata.integration_class, PlannerIntegrationClass::App)
                && matches!(metadata.side_effect_level, PlannerSideEffectLevel::Write)
                && (content_lower.contains("http://")
                    || content_lower.contains("https://")
                    || content_lower.contains("access_url")
                    || content_lower.contains("open app")))
    })
}

fn response_is_meta_tool_summary(text: &str) -> bool {
    let trimmed = text.trim();
    if trimmed.is_empty() {
        return false;
    }
    let lower = trimmed.to_ascii_lowercase();
    if lower.starts_with("called tools:") {
        return true;
    }
    let lines: Vec<&str> = trimmed.lines().collect();
    lines.len() <= 6
        && lines.iter().any(|line| {
            line.trim()
                .to_ascii_lowercase()
                .starts_with("called tools:")
        })
}

fn append_preserved_tool_outputs(response: &mut String, preserved_outputs: &[String]) {
    let mut seen: HashSet<&str> = HashSet::new();
    for output in preserved_outputs {
        let trimmed = output.trim();
        if trimmed.is_empty() || !seen.insert(trimmed) {
            continue;
        }
        if response.contains(trimmed) {
            continue;
        }
        if !response.trim().is_empty() {
            response.push_str("\n\n");
        }
        response.push_str(trimmed);
    }
}

#[cfg(test)]
fn pin_preferred_actions(
    selected: &mut Vec<crate::actions::ActionDef>,
    all_actions: &[crate::actions::ActionDef],
    preferred_action_names: &[String],
    limit: usize,
) {
    if preferred_action_names.is_empty() {
        return;
    }

    let mut pinned = Vec::new();
    for action_name in preferred_action_names {
        if selected
            .iter()
            .any(|action| action.name.eq_ignore_ascii_case(action_name))
        {
            continue;
        }
        if let Some(action) = all_actions
            .iter()
            .find(|action| action.name.eq_ignore_ascii_case(action_name))
        {
            pinned.push(action.clone());
        }
    }

    if pinned.is_empty() {
        return;
    }

    pinned.append(selected);
    *selected = pinned;
    if selected.len() > limit {
        selected.truncate(limit);
    }
}

fn action_supports_orchestration(action: &crate::actions::ActionDef) -> bool {
    matches!(
        action.planner_metadata().role,
        PlannerActionRole::Orchestration
    )
}

fn action_supports_filesystem_read(action: &crate::actions::ActionDef) -> bool {
    let metadata = action.planner_metadata();
    action_is_read_only(action)
        && matches!(metadata.role, PlannerActionRole::Inspection)
        && matches!(
            metadata.integration_class,
            PlannerIntegrationClass::Filesystem
        )
}

fn action_supports_filesystem_write(action: &crate::actions::ActionDef) -> bool {
    let metadata = action.planner_metadata();
    matches!(metadata.role, PlannerActionRole::Mutation)
        && matches!(
            metadata.integration_class,
            PlannerIntegrationClass::Filesystem
        )
}

fn action_supports_code_mutation(action: &crate::actions::ActionDef) -> bool {
    let metadata = action.planner_metadata();
    matches!(metadata.role, PlannerActionRole::Mutation)
        && matches!(metadata.integration_class, PlannerIntegrationClass::Code)
}

fn action_supports_app_inspection(action: &crate::actions::ActionDef) -> bool {
    let metadata = action.planner_metadata();
    action_is_read_only(action)
        && matches!(metadata.role, PlannerActionRole::Inspection)
        && matches!(metadata.integration_class, PlannerIntegrationClass::App)
}

fn action_supports_app_mutation(action: &crate::actions::ActionDef) -> bool {
    let metadata = action.planner_metadata();
    matches!(metadata.role, PlannerActionRole::Mutation)
        && matches!(metadata.integration_class, PlannerIntegrationClass::App)
}

fn append_best_matching_action(
    selected: &mut Vec<crate::actions::ActionDef>,
    all_actions: &[crate::actions::ActionDef],
    limit: usize,
    predicate: impl Fn(&crate::actions::ActionDef) -> bool,
) {
    if selected.len() >= limit {
        return;
    }

    let selected_names = selected
        .iter()
        .map(|action| action.name.to_ascii_lowercase())
        .collect::<HashSet<_>>();
    if let Some(action) = all_actions.iter().find(|action| {
        !selected_names.contains(&action.name.to_ascii_lowercase()) && predicate(action)
    }) {
        selected.push(action.clone());
    }
}

fn expand_action_shortlist_with_semantic_companions(
    selected: &mut Vec<crate::actions::ActionDef>,
    all_actions: &[crate::actions::ActionDef],
    app_deploy_intent: bool,
    schedule_task_intent: bool,
    watch_intent: bool,
    use_recent_artifact_context: bool,
    workspace_modification_request: bool,
    limit: usize,
) {
    let has_orchestration =
        schedule_task_intent || watch_intent || selected.iter().any(action_supports_orchestration);
    let has_app_domain = app_deploy_intent
        || selected.iter().any(|action| {
            action_supports_app_inspection(action) || action_supports_app_mutation(action)
        });

    if (schedule_task_intent || watch_intent) && !selected.iter().any(action_supports_orchestration)
    {
        append_best_matching_action(selected, all_actions, limit, action_supports_orchestration);
    }

    if app_deploy_intent && !selected.iter().any(action_supports_app_mutation) {
        append_best_matching_action(selected, all_actions, limit, action_supports_app_mutation);
    }

    if has_app_domain || use_recent_artifact_context {
        append_best_matching_action(
            selected,
            all_actions,
            limit,
            action_supports_filesystem_read,
        );
        append_best_matching_action(selected, all_actions, limit, action_supports_app_inspection);
        if app_deploy_intent || workspace_modification_request || use_recent_artifact_context {
            append_best_matching_action(
                selected,
                all_actions,
                limit,
                action_supports_filesystem_write,
            );
        }
    }

    if has_orchestration {
        append_best_matching_action(selected, all_actions, limit, action_supports_code_mutation);
    }

    if workspace_modification_request && !has_app_domain {
        append_best_matching_action(
            selected,
            all_actions,
            limit,
            action_supports_filesystem_read,
        );
        append_best_matching_action(
            selected,
            all_actions,
            limit,
            action_supports_filesystem_write,
        );
        append_best_matching_action(selected, all_actions, limit, action_supports_code_mutation);
    }

    if selected.len() > limit {
        selected.truncate(limit);
    }
}

fn should_apply_recent_artifact_context(
    message: &str,
    all_actions: &[crate::actions::ActionDef],
    recent_artifact: Option<&ConversationArtifactContext>,
    has_recent_artifact_context: bool,
    continuation_score: f32,
    artifact_reference: f32,
    competing_intent: f32,
) -> bool {
    let _ = (
        message,
        all_actions,
        recent_artifact,
        has_recent_artifact_context,
        continuation_score,
        artifact_reference,
        competing_intent,
    );
    false
}

/// Query complexity classification
#[derive(Debug, Clone, Copy, PartialEq, serde::Serialize, serde::Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum QueryComplexity {
    /// Simple query - direct response
    Simple,
    /// Medium complexity - direct response with normal routing/failover
    Medium,
    /// Complex multi-step task - use orchestra
    Complex,
}

fn confirmed_plan_uses_read_only_research_actions(
    plan: &ExecutionPlan,
    available_actions: &[crate::actions::ActionDef],
) -> bool {
    let referenced_names = confirmed_plan_action_names(plan);
    referenced_names.is_empty()
        || referenced_names.iter().all(|name| {
            available_actions
                .iter()
                .find(|action| action.name.eq_ignore_ascii_case(name))
                .is_some_and(action_is_read_only_knowledge_action)
        })
}

fn confirmed_plan_step_branch_task(step: &PlanStep) -> String {
    let mut sections = vec![format!(
        "Own approved deep-research plan step {}: {}",
        step.id, step.title
    )];
    if !step.description.trim().is_empty() {
        sections.push(step.description.trim().to_string());
    }
    if !step.substeps.is_empty() {
        sections.push(format!(
            "Subtasks:\n{}",
            step.substeps
                .iter()
                .map(|substep| format!("- {}", substep.title.trim()))
                .collect::<Vec<_>>()
                .join("\n")
        ));
    }
    sections.push(
        "Stay on this step only. Gather or verify the evidence needed for this branch and return the highest-signal findings, risks, and cited takeaways for the coordinator."
            .to_string(),
    );
    sections.join("\n\n")
}

fn confirmed_plan_step_is_synthesis(step: &PlanStep) -> bool {
    let text = format!("{} {}", step.title, step.description).to_ascii_lowercase();
    [
        "synthes",
        "final answer",
        "final report",
        "recommend",
        "policy option",
        "conclusion",
        "write",
    ]
    .iter()
    .any(|needle| text.contains(needle))
}

fn build_confirmed_plan_delegation_specs(
    plan: &ExecutionPlan,
    deep_research_requested: bool,
    available_actions: &[crate::actions::ActionDef],
) -> Vec<super::task_router::SubAgentSpec> {
    if !deep_research_requested || plan.steps.len() < 2 {
        return Vec::new();
    }
    if !confirmed_plan_uses_read_only_research_actions(plan, available_actions) {
        return Vec::new();
    }

    let mut specs = Vec::new();
    for step in &plan.steps {
        match execution_plan_step_status(step) {
            PlanStepStatus::Failed | PlanStepStatus::Skipped => continue,
            PlanStepStatus::Pending | PlanStepStatus::Running | PlanStepStatus::Completed => {}
        }

        let synthesis_like = confirmed_plan_step_is_synthesis(step);
        let depends_on = if synthesis_like && !specs.is_empty() {
            (0..specs.len()).collect::<Vec<_>>()
        } else {
            Vec::new()
        };
        specs.push(super::task_router::SubAgentSpec {
            agent_type: if synthesis_like {
                "Writer".to_string()
            } else {
                "Researcher".to_string()
            },
            task: confirmed_plan_step_branch_task(step),
            preferred_model_role: if synthesis_like {
                None
            } else {
                Some("Research".to_string())
            },
            depends_on,
            plan_step_id: Some(step.id),
        });
    }

    let independent_branches = specs
        .iter()
        .filter(|spec| spec.depends_on.is_empty())
        .count();
    if specs.len() < 2 || independent_branches < 2 {
        return Vec::new();
    }
    specs
}

fn confirmed_plan_routing_decision(
    plan: Option<&ExecutionPlan>,
    deep_research_requested: bool,
    available_actions: &[crate::actions::ActionDef],
) -> super::task_router::RoutingDecision {
    let sub_agents = plan
        .map(|plan| {
            build_confirmed_plan_delegation_specs(plan, deep_research_requested, available_actions)
        })
        .unwrap_or_default();
    if !sub_agents.is_empty() {
        return super::task_router::RoutingDecision {
            needs_delegation: true,
            complexity: QueryComplexity::Complex,
            sub_agents,
            reasoning:
                "A confirmed deep-research plan contains independent read-only branches, so skip router exploration and execute the approved plan through delegated specialists."
                    .to_string(),
            confidence: 1.0,
            should_clarify: false,
            clarification_question: None,
        };
    }

    super::task_router::RoutingDecision {
        needs_delegation: false,
        complexity: QueryComplexity::Complex,
        sub_agents: Vec::new(),
        reasoning:
            "A confirmed execution plan is already approved, so skip router exploration and continue directly with the plan."
                .to_string(),
        confidence: 1.0,
        should_clarify: false,
        clarification_question: None,
    }
}

fn should_generate_execution_plan(
    execution_intent: bool,
    ambiguous_request: bool,
    complexity: QueryComplexity,
    _app_deploy_intent: bool,
    _automation_orchestration_intent: bool,
    pause_for_plan_confirmation: bool,
) -> bool {
    if ambiguous_request {
        return false;
    }
    if pause_for_plan_confirmation {
        return true;
    }
    execution_intent && complexity == QueryComplexity::Complex
}

/// Conversation message for history tracking
