fn build_specialized_app_prompt_guidance(message: &str, app_deploy_intent: bool) -> String {
    if !app_deploy_intent {
        return String::new();
    }

    let repo_source_requested = request_mentions_repo_source(message);
    let mut sections: Vec<Vec<&'static str>> = Vec::new();

    if repo_source_requested {
        sections.push(vec![
            "## Repo Deploy Guidance",
            "- This is a repo-based live app request. Use the repository directly; do not replace it with a newly generated app or scaffold unless the user explicitly asks for that fallback.",
            "- The primary path is `app_deploy` with `repo_url` so the runtime can clone the repository, inspect local manifests, detect the correct runtime, install dependencies, and start the server.",
            "- Treat repo deploy as an end-to-end runtime task: clone, detect, install, start, and then return the working local AgentArk URL.",
            "- Verify that the deployed app is actually reachable before finishing. Prefer validation via runtime checks, local HTTP request, or logs that confirm the app is serving successfully.",
            "- If the first start fails, inspect the app logs or runtime output, adjust the deploy/runtime choice when needed, and retry automatically instead of stopping after the first failed attempt.",
            "- Finish only when the app is reachable locally, or when you have a concrete blocking error that cannot be resolved automatically.",
        ]);
    }
    sections
        .into_iter()
        .map(|section| section.join("\n"))
        .collect::<Vec<_>>()
        .join("\n")
}

fn extract_literal_target_references(message: &str) -> Vec<String> {
    let mut targets = Vec::new();
    let mut seen = HashSet::new();

    if let Ok(url_re) = regex::Regex::new(r#"(?i)\b[a-z][a-z0-9+.-]*://[^\s`"'<>)]+"#) {
        for capture in url_re.find_iter(message) {
            let target = capture
                .as_str()
                .trim()
                .trim_end_matches(['.', ',', ';', ':']);
            if !target.is_empty() && seen.insert(target.to_string()) {
                targets.push(target.to_string());
                if targets.len() >= 3 {
                    return targets;
                }
            }
        }
    }

    if let Ok(ip_re) = regex::Regex::new(r#"\b(?:\d{1,3}\.){3}\d{1,3}(?::\d{1,5})?\b"#) {
        for capture in ip_re.find_iter(message) {
            let target = capture.as_str().trim();
            if !target.is_empty() && seen.insert(target.to_string()) {
                targets.push(target.to_string());
                if targets.len() >= 3 {
                    break;
                }
            }
        }
    }

    targets
}

fn render_execution_target_block(targets: &[String]) -> String {
    if targets.is_empty() {
        return String::new();
    }

    let mut block = String::from("<agentark_current_turn_execution_targets>\n");
    for target in targets {
        block.push_str("target: ");
        block.push_str(target);
        block.push('\n');
    }
    block.push_str("</agentark_current_turn_execution_targets>");
    block
}

fn build_specialized_monitoring_prompt_guidance(message: &str, watch_intent: bool) -> String {
    if !watch_intent {
        return String::new();
    }

    let mut lines = vec![
        "## Monitoring Guidance".to_string(),
        "- This request asks for ongoing monitoring or alerting. Do not answer with a generic capability disclaimer when local automation tools are available.".to_string(),
        "- Prefer `watch` for recurring monitoring, especially sub-minute cadences such as every 10 seconds.".to_string(),
        "- If the target needs a custom poller, runtime dependencies, or local device/network access, use a companion execution tool such as `code_execute` to set that up and validate it.".to_string(),
        "- Preserve user-supplied targets exactly. If the request already includes a URL, IP, hostname, path, or device endpoint, copy that literal value into tool arguments and code. Do not replace it with placeholders such as `[IP]`, `YOUR_IP`, or sample endpoints.".to_string(),
        "- Validate the live target with the lightest viable probe first. Prefer a dependency-light connectivity or protocol check before installing heavier CV/ML packages.".to_string(),
        "- For live-target monitoring, do not substitute mock, stub, simulated, or fake data. Use the real target or return a real failure.".to_string(),
        "- Every `code_execute` call must include the required `language` and `code` fields. Do not emit partial placeholder execution calls.".to_string(),
        "- When you use `code_execute` for a staged monitoring flow, include `execution_contract.phase` with one of: `bootstrap`, `validate`, or `poll`.".to_string(),
        "- For validation or polling steps that prove the monitor is ready, also set `execution_contract.target_validated_when_successful=true` and `execution_contract.ready_for_watch_when_successful=true`.".to_string(),
        "- If a staged monitoring step must reach a live target such as a LAN device, network stream, URL, API, or other device endpoint, set `execution_contract.target_connectivity_required=true`.".to_string(),
        "- Every `watch` call must include a structured `condition` object. Prefer `type=json_predicate` or `type=json_logic` when the poller returns structured JSON. Use `type=llm` only when the trigger cannot be expressed safely as an explicit contract.".to_string(),
        "- For visual, camera, video, screen, or media monitoring, make the poller return actionable evidence when available: save a representative `.jpg`/`.png` snapshot as an output file, return structured fields for counts/status plus any grounded observation/activity text, and use `Not provided` or `unknown` rather than guessing when activity is not inferable.".to_string(),
        "- A setup-only dependency installer is not enough. The setup phase should produce or validate the actual runnable poller before you hand off to `watch`.".to_string(),
        "- After setup succeeds, emit a `watch` tool call instead of stopping in prose. For custom monitors, prefer `watch` with `poll_action=\"code_execute\"` and reuse the validated execution arguments in `poll_arguments`.".to_string(),
        "- AgentArk is running locally. Private-network targets, LAN devices, intranet services, and other local endpoints may be reachable from execution tools. Do not claim they are inaccessible unless an actual connectivity attempt has already failed.".to_string(),
        "- Finish by creating the actual watcher or monitoring loop, not by only describing how the user could do it manually.".to_string(),
    ];
    let literal_targets = extract_literal_target_references(message);
    if !literal_targets.is_empty() {
        lines.push("- Current request targets are provided in the trusted execution-target block below. Reuse these exact literals when you build tool arguments.".to_string());
        lines.push(render_execution_target_block(&literal_targets));
    }

    lines.join("\n")
}

