    #[test]
    fn ambient_intent_keys_are_stable_and_scoped() {
        let first = ambient_intent_keys("Title", "Content", Some("conversation-a"), None);
        let second = ambient_intent_keys("Title", "Content", Some("conversation-a"), None);
        let other_scope = ambient_intent_keys("Title", "Content", Some("conversation-b"), None);

        assert_eq!(first, second);
        assert_ne!(first, other_scope);
        assert!(first.0.starts_with("ambient-intent-"));
        assert!(first.1.starts_with("ambient_intent::"));
    }

    #[test]
    fn ambient_intent_due_respects_next_revisit_and_expiry() {
        let now = chrono::DateTime::parse_from_rfc3339("2026-04-12T10:00:00Z")
            .expect("valid timestamp")
            .with_timezone(&chrono::Utc);
        let due_item = test_ambient_item(now - chrono::Duration::minutes(1), None);
        let future_item = test_ambient_item(now + chrono::Duration::minutes(1), None);
        let expired_item = test_ambient_item(
            now - chrono::Duration::minutes(1),
            Some(now - chrono::Duration::seconds(1)),
        );

        assert!(ambient_intent_due(&due_item, now));
        assert!(!ambient_intent_due(&future_item, now));
        assert!(ambient_intent_expired(&expired_item, now));
        assert!(!ambient_intent_due(&expired_item, now));
    }

