    fn cli_skill_markdown(
        name: &str,
        description: &str,
        install_command: &str,
        verify_command: &str,
        extra_body: &str,
    ) -> String {
        let install_block = if cfg!(windows) {
            format!(
                "```powershell\n# Windows (PowerShell)\n{}\n# macOS / Linux\nprintf install-skipped\n```",
                install_command
            )
        } else {
            format!(
                "```bash\n# macOS / Linux\n{}\n# Windows (PowerShell)\nWrite-Output install-skipped\n```",
                install_command
            )
        };
        format!(
            "---\nname: {name}\ndescription: {description}\nversion: \"1.0.0\"\n---\n# {name}\n\n## Install & Update\n{install_block}\n\nVerify: `{verify_command}`\n\n{extra_body}\n"
        )
    }

    async fn seed_conversation(agent: &Agent, conversation_id: &str, messages: &[(&str, String)]) {
        let now = chrono::Utc::now();
        agent
            .storage
            .create_conversation(&crate::storage::entities::conversation::Model {
                id: conversation_id.to_string(),
                title: "Test Conversation".to_string(),
                channel: "web".to_string(),
                project_id: None,
                created_at: now.to_rfc3339(),
                updated_at: now.to_rfc3339(),
                message_count: 0,
                archived: false,
                starred: false,
            })
            .await
            .expect("conversation should be created");

        for (idx, (role, content)) in messages.iter().enumerate() {
            agent
                .encrypted_storage
                .insert_message_encrypted(&crate::storage::entities::message::Model {
                    id: format!("{}-{}", conversation_id, idx),
                    conversation_id: conversation_id.to_string(),
                    role: (*role).to_string(),
                    content: content.clone(),
                    timestamp: (now + chrono::Duration::seconds(idx as i64)).to_rfc3339(),
                    model_used: None,
                    trace_id: None,
                })
                .await
                .expect("message should be inserted");
        }
    }

