    fn extract_backticked_id(message: &str, label: &str) -> Option<String> {
        let (_, tail) = message.split_once(label)?;
        let (_, tail) = tail.split_once('`')?;
        let (value, _) = tail.split_once('`')?;
        Some(value.to_string())
    }

