    #[tokio::test]
    async fn recent_artifact_context_keeps_multiple_items_and_selects_by_message() {
        let (agent, _config_dir, _data_dir) = build_test_agent().await;
        let conversation_id = "recent-artifacts-multi";
        let task_alpha = crate::core::Task::new(
            "Track pricing changes".to_string(),
            "research".to_string(),
            serde_json::json!({ "query": "pricing changes" }),
        );
        let task_beta = crate::core::Task::new(
            "Watch reinforcement learning papers".to_string(),
            "research".to_string(),
            serde_json::json!({ "query": "reinforcement learning papers" }),
        );
        let alpha_id = task_alpha.id.to_string();
        let beta_id = task_beta.id.to_string();
        agent
            .add_task(task_alpha)
            .await
            .expect("alpha task should exist");
        agent
            .add_task(task_beta)
            .await
            .expect("beta task should exist");

        agent
            .persist_conversation_artifact_context(
                conversation_id,
                ConversationArtifactSpec {
                    artifact_type: "task",
                    artifact_id: &alpha_id,
                    title: "Track pricing changes",
                    summary: "Pricing monitor task",
                    url: None,
                    related_actions: &["list_tasks"],
                },
            )
            .await;
        agent
            .persist_conversation_artifact_context(
                conversation_id,
                ConversationArtifactSpec {
                    artifact_type: "task",
                    artifact_id: &beta_id,
                    title: "Watch reinforcement learning papers",
                    summary: "RL papers task",
                    url: None,
                    related_actions: &["list_tasks"],
                },
            )
            .await;

        let artifacts = agent.load_recent_artifact_contexts(conversation_id).await;
        assert_eq!(artifacts.len(), 2);
        let selected = Agent::select_recent_artifact_for_message(
            &artifacts,
            &format!("actually change {} instead", beta_id),
        )
        .expect("artifact should be selected");
        assert_eq!(selected.artifact_id, beta_id);
    }

