    #[test]
    fn detect_external_cli_skill_spec_extracts_install_and_verify_commands() {
        let content = r#"---
name: officecli
description: Office CLI
version: "1.2.3"
---
# officecli

## Install & Update
```bash
# macOS / Linux
curl -fsSL https://example.com/install.sh | bash
# Windows (PowerShell)
irm https://example.com/install.ps1 | iex
```

Verify: `officecli --version`
"#;

        let spec = detect_external_cli_skill_spec(content).expect("skill should be detected");
        assert_eq!(spec.name, "officecli");
        if cfg!(windows) {
            assert!(spec.install_command.starts_with("irm "));
        } else {
            assert!(spec.install_command.starts_with("curl "));
        }
        assert_eq!(spec.verify_command, "officecli --version");
        assert_eq!(spec.executable_name, "officecli");
    }

    #[test]
    fn detect_external_cli_skill_spec_requires_platform_compatible_install_command() {
        let content = r#"---
name: officecli
description: Office CLI
version: "1.2.3"
---
# officecli

## Install & Update
```bash
# macOS / Linux
curl -fsSL https://example.com/install.sh | bash
```

Verify: `officecli --version`
"#;

        let spec = detect_external_cli_skill_spec(content);
        if cfg!(windows) {
            assert!(spec.is_none());
        } else {
            assert!(spec.is_some());
        }
    }

