    #[tokio::test]
    async fn sensitive_context_followup_creates_awaiting_approval_task() {
        let (agent, _config_dir, _data_dir) = build_test_agent().await;
        let (task_id, reused_existing, duplicates_removed) = agent
            .queue_sensitive_context_approval_task(
                "Summarize my inbox",
                "web",
                Some("conv-sensitive"),
                None,
                &["gmail_scan".to_string()],
                &["street-address-like content detected in model input".to_string()],
            )
            .await
            .expect("approval task should be created");

        assert!(!reused_existing);
        assert_eq!(duplicates_removed, 0);

        let tasks = agent.tasks.read().await;
        let task = tasks
            .all()
            .iter()
            .find(|task| task.id == task_id)
            .expect("approval task should be queued");
        assert_eq!(task.action, "sensitive_context_followup");
        assert!(matches!(
            task.status,
            crate::core::TaskStatus::AwaitingApproval
        ));
        assert_eq!(
            task.arguments
                .get("_approval")
                .and_then(|value| value.get("title"))
                .and_then(|value| value.as_str()),
            Some("Sensitive context approval")
        );
        assert_eq!(
            task.arguments
                .get("_approval")
                .and_then(|value| value.get("source"))
                .and_then(|value| value.as_str()),
            Some("chat_privacy_guard")
        );
        assert_eq!(
            task.arguments
                .get("allow_sensitive_model_context_once")
                .and_then(|value| value.as_bool()),
            Some(true)
        );
    }

    #[test]
    fn context_dependent_followup_detector_catches_short_answers_to_questions() {
        let history = vec![
            ConversationMessage {
                role: "user".to_string(),
                content: "what is my name".to_string(),
                _timestamp: chrono::Utc::now(),
            },
            ConversationMessage {
                role: "assistant".to_string(),
                content: "I don't have your name yet. What should I call you?".to_string(),
                _timestamp: chrono::Utc::now(),
            },
        ];

        assert!(is_context_dependent_followup_message("Taylor", &history));
        assert!(is_context_dependent_followup_message(
            "Asia/Kolkata",
            &history
        ));
    }

    #[test]
    fn context_dependent_followup_detector_ignores_standalone_smalltalk() {
        let history = vec![ConversationMessage {
            role: "assistant".to_string(),
            content: "The app is running now.".to_string(),
            _timestamp: chrono::Utc::now(),
        }];

        assert!(!is_context_dependent_followup_message("hello", &history));
        assert!(!is_context_dependent_followup_message(
            "how are you?",
            &history
        ));
        assert!(!is_context_dependent_followup_message(
            "thanks for the help",
            &history
        ));
    }

