    #[test]
    fn structured_watcher_condition_contract_evaluates_json_without_model() {
        let condition = crate::core::watcher::WatchCondition {
            description: "Trigger when a new person is detected".to_string(),
            matcher: crate::core::watcher::WatchConditionMatcher::JsonLogic {
                logic: crate::core::watcher::WatchConditionLogic::Any,
                rules: vec![
                    crate::core::watcher::WatchJsonPredicate {
                        path: "new_persons".to_string(),
                        operator: crate::core::watcher::WatchConditionOperator::Gt,
                        value: Some(serde_json::json!(0)),
                    },
                    crate::core::watcher::WatchJsonPredicate {
                        path: "status".to_string(),
                        operator: crate::core::watcher::WatchConditionOperator::Eq,
                        value: Some(serde_json::json!("NEW_PERSON_DETECTED")),
                    },
                ],
            },
        };
        let result = concat!(
            "AgentArk auto-installed sandbox dependencies: numpy, opencv-python-headless\n",
            "{\"person_count\":2,\"baseline\":2,\"new_persons\":0,\"status\":\"NO_NEW_PERSONS\"}"
        );
        assert_eq!(
            Agent::evaluate_watch_condition_without_llm(&condition, result),
            Some(Ok(false))
        );

        let result = "{\"new_persons\":1,\"status\":\"NEW_PERSON_DETECTED\"}";
        assert_eq!(
            Agent::evaluate_watch_condition_without_llm(&condition, result),
            Some(Ok(true))
        );
    }

    #[test]
    fn structured_watcher_condition_supports_dollar_prefixed_json_paths() {
        let condition = crate::core::watcher::WatchCondition {
            description: "Trigger when at least one person is detected".to_string(),
            matcher: crate::core::watcher::WatchConditionMatcher::JsonPredicate {
                path: "$.persons_detected".to_string(),
                operator: crate::core::watcher::WatchConditionOperator::Gt,
                value: Some(serde_json::json!(0)),
            },
        };
        let result = serde_json::json!({
            "output": "{\"persons_detected\":3,\"status\":\"success\"}",
            "agentark_execution": {
                "phase": "poll",
                "ready_for_watch": true,
                "target_validated": true
            }
        })
        .to_string();
        assert_eq!(
            Agent::evaluate_watch_condition_without_llm(&condition, &result),
            Some(Ok(true))
        );
    }

