    #[tokio::test]
    async fn repair_unrecoverable_approval_tasks_cancels_unreadable_pending_approvals() {
        let (agent, _config_dir, _data_dir) = build_test_agent().await;
        let task = Task {
            id: uuid::Uuid::new_v4(),
            description: crate::storage::ENCRYPTED_STORAGE_UNAVAILABLE.to_string(),
            action: "delegate".to_string(),
            arguments: serde_json::json!({}),
            approval: crate::core::TaskApproval::RequireApproval,
            capabilities: vec![],
            status: TaskStatus::AwaitingApproval,
            created_at: chrono::Utc::now(),
            scheduled_for: None,
            cron: None,
            result: None,
            proof_id: None,
            priority: None,
            urgency: None,
            importance: None,
            eisenhower_quadrant: None,
        };

        agent
            .storage
            .insert_task(&task)
            .await
            .expect("task should be persisted");
        {
            let mut tasks = agent.tasks.write().await;
            tasks.add(task.clone());
        }

        let repaired = agent
            .repair_unrecoverable_approval_tasks()
            .await
            .expect("repair should succeed");
        assert_eq!(repaired, 1);

        let repaired_task = {
            let tasks = agent.tasks.read().await;
            tasks
                .all()
                .iter()
                .find(|queued| queued.id == task.id)
                .cloned()
                .expect("task should still exist")
        };
        assert!(matches!(repaired_task.status, TaskStatus::Cancelled));
        assert!(repaired_task
            .result
            .as_deref()
            .unwrap_or_default()
            .contains("could not be restored after restart"));

        let stored_task = agent
            .storage
            .get_tasks()
            .await
            .expect("stored tasks should load")
            .into_iter()
            .find(|row| row.id == task.id.to_string())
            .expect("stored task should exist");
        assert!(stored_task.status.contains("Cancelled"));
        assert!(stored_task
            .result
            .as_deref()
            .unwrap_or_default()
            .contains("could not be restored after restart"));
    }

