    #[test]
    fn execution_plan_trace_payload_persists_terminal_statuses() {
        let now = chrono::Utc::now();
        let mut trace = ExecutionTrace {
            id: "trace-plan".to_string(),
            message: "deploy app".to_string(),
            channel: "test".to_string(),
            started_at: Some(now),
            completed_at: None,
            steps: vec![ExecutionStep {
                icon: "[plan]".to_string(),
                title: "Execution Plan".to_string(),
                detail: "2 steps planned".to_string(),
                step_type: "plan".to_string(),
                data: None,
                timestamp: now,
                duration_ms: Some(10),
            }],
            proof_id: None,
            response: None,
            model: None,
            input_tokens: 0,
            output_tokens: 0,
            total_tokens: 0,
            cost_usd: 0.0,
            complexity: None,
            plan: Some(test_execution_plan(
                "plan-trace",
                1,
                "Deploy the app",
                vec![
                    test_plan_step(
                        1,
                        "Create files",
                        "Write the app bundle",
                        Some("file_write"),
                        PlanStepStatus::Pending,
                    ),
                    test_plan_step(
                        2,
                        "Deploy",
                        "Launch the app",
                        Some("app_deploy"),
                        PlanStepStatus::Pending,
                    ),
                ],
            )),
        };

        mark_execution_plan_started(&mut trace);
        mark_execution_plan_completed(&mut trace);

        let stored = trace.steps[0]
            .data
            .as_ref()
            .expect("plan trace step should contain serialized plan");
        let parsed: ExecutionPlan =
            serde_json::from_str(stored).expect("serialized plan should be valid JSON");
        assert_eq!(parsed.plan_id, "plan-trace");
        assert_eq!(parsed.revision, 1);
        assert_eq!(parsed.steps.len(), 2);
        assert_eq!(parsed.steps[0].status, Some(PlanStepStatus::Completed));
        assert_eq!(parsed.steps[1].status, Some(PlanStepStatus::Pending));
    }

