    #[test]
    fn monitoring_watch_handoff_requires_successful_setup_without_existing_watch() {
        let batch = crate::core::agent::tool_execution::ToolExecutionBatch {
            outputs: vec![crate::core::agent::tool_execution::ToolCallOutput {
                name: "code_execute".to_string(),
                content: serde_json::json!({
                    "output": "validated",
                    "error": serde_json::Value::Null,
                    "exit_code": 0,
                    "agentark_execution": {
                        "phase": "validate",
                        "setup_only": false,
                        "target_validated": true,
                        "ready_for_watch": true,
                        "network_access_requested": true,
                        "output_file_count": 1
                    }
                })
                .to_string(),
            }],
            outcomes: vec![crate::core::ToolOutcome {
                name: "code_execute".to_string(),
                content: "validated".to_string(),
                status: crate::core::ToolOutcomeStatus::Success,
                failure_class: None,
                retryable: false,
                side_effect_level: "sandbox".to_string(),
                error: None,
            }],
        };

        assert!(should_force_monitoring_watch_handoff(
            true,
            &[test_tool_call(
                "code_execute",
                serde_json::json!({
                    "language": "python",
                    "execution_contract": {
                        "phase": "validate",
                        "target_validated_when_successful": true,
                        "ready_for_watch_when_successful": true
                    }
                }),
            )],
            &[],
            &batch,
            0,
        ));
        assert!(!should_force_monitoring_watch_handoff(
            true,
            &[test_tool_call(
                "watch",
                serde_json::json!({ "description": "monitor" })
            )],
            &[test_tool_call(
                "watch",
                serde_json::json!({ "description": "monitor" })
            )],
            &batch,
            0,
        ));
    }

