    #[test]
    fn monitoring_recovery_synthesizes_post_baseline_watch_from_failed_watch_and_structured_poll() {
        let prior_watch = test_tool_call(
            "watch",
            serde_json::json!({
                "description": "Tell me if there is a new person detected",
                "poll_action": "rtsp-person-detect",
                "poll_arguments": {
                    "url": "customproto://camera.local/front"
                },
                "condition": {
                    "description": "Trigger when person_count is greater than zero",
                    "type": "json_predicate",
                    "path": "$.person_count",
                    "operator": "gt",
                    "value": 0
                },
                "on_trigger": "Notify me when a new person appears"
            }),
        );
        let code_execute_call = test_tool_call(
            "code_execute",
            serde_json::json!({
                "language": "python",
                "code": "print('validated')",
                "execution_contract": {
                    "phase": "validate",
                    "target_validated_when_successful": true,
                    "ready_for_watch_when_successful": false
                }
            }),
        );
        let batch = crate::core::agent::tool_execution::ToolExecutionBatch {
            outputs: vec![crate::core::agent::tool_execution::ToolCallOutput {
                name: "code_execute".to_string(),
                content: serde_json::json!({
                    "output": "{\"person_count\":2,\"status\":\"PERSON_PRESENT\"}",
                    "error": serde_json::Value::Null,
                    "exit_code": 0,
                    "agentark_execution": {
                        "phase": "validate",
                        "setup_only": false,
                        "target_validated": true,
                        "ready_for_watch": false,
                        "network_access_requested": true,
                        "output_file_count": 0
                    }
                })
                .to_string(),
            }],
            outcomes: vec![crate::core::ToolOutcome {
                name: "code_execute".to_string(),
                content: "validated".to_string(),
                status: crate::core::ToolOutcomeStatus::Success,
                failure_class: None,
                retryable: false,
                side_effect_level: "sandbox".to_string(),
                error: None,
            }],
        };

        assert!(monitoring_code_execute_has_structured_poller_output(
            true,
            std::slice::from_ref(&code_execute_call),
            std::slice::from_ref(&prior_watch),
            &batch,
        ));

        let synthesized = synthesize_monitoring_watch_call_from_recent_code_execute(
            std::slice::from_ref(&code_execute_call),
            std::slice::from_ref(&prior_watch),
            &batch,
        )
        .expect("watch should be synthesized from the validated poller output");

        assert_eq!(synthesized.name, "watch");
        assert_eq!(
            synthesized
                .arguments
                .get("poll_action")
                .and_then(|value| value.as_str()),
            Some("code_execute")
        );
        assert_eq!(
            synthesized.arguments.get("poll_arguments"),
            Some(&code_execute_call.arguments)
        );

        let condition: crate::core::watcher::WatchCondition = serde_json::from_value(
            synthesized
                .arguments
                .get("condition")
                .cloned()
                .expect("condition should be present"),
        )
        .expect("condition should deserialize");
        match condition.matcher {
            crate::core::watcher::WatchConditionMatcher::JsonPredicate {
                path,
                operator,
                value,
            } => {
                assert_eq!(path, "$.person_count");
                assert_eq!(operator, crate::core::watcher::WatchConditionOperator::Gt);
                assert_eq!(value, Some(serde_json::json!(2)));
            }
            other => panic!("expected json_predicate condition, got {:?}", other),
        }
    }

