    #[tokio::test]
    async fn recoverable_tool_failure_keeps_parent_step_running_for_retry() {
        let trace_ref = Arc::new(RwLock::new(ExecutionTrace {
            plan: Some(test_execution_plan(
                "plan-retry",
                1,
                "Research the topic",
                vec![test_plan_step(
                    1,
                    "Gather sources",
                    "Use research",
                    Some("research"),
                    PlanStepStatus::Running,
                )],
            )),
            ..ExecutionTrace::default()
        }));

        update_execution_plan_for_tool_start(
            &trace_ref,
            None,
            &test_tool_call(
                "research",
                serde_json::json!({ "query": "gather india ai sources" }),
            ),
        )
        .await;
        update_execution_plan_for_tool_result(
            &trace_ref,
            None,
            "research",
            false,
            Some(&crate::core::ToolOutcomeStatus::RecoverableError),
        )
        .await;

        let trace = trace_ref.read().await;
        let plan = trace.plan.as_ref().expect("plan should exist");
        assert_eq!(plan.steps[0].status, Some(PlanStepStatus::Running));
        assert_eq!(plan.steps[0].substeps.len(), 1);
        assert_eq!(
            plan.steps[0].substeps[0].status,
            Some(PlanStepStatus::Failed)
        );
    }

    #[test]
    fn security_events_commit_snapshot_preserves_newer_events() {
        let events = SecurityEvents::new();
        events.record_auth_failure();
        events.record_auth_failure();

        let first_snapshot = events.snapshot();
        assert_eq!(first_snapshot.auth_failures, 2);

        events.record_auth_failure();
        events.commit_snapshot(&first_snapshot);

        let second_snapshot = events.snapshot();
        assert_eq!(second_snapshot.auth_failures, 1);
    }
